/* ═══════════ TOAST SYSTEM ═══════════ */
let _toastListener = null
function showToast(message, type = 'success') {
  if (_toastListener) _toastListener({ message, type, id: Date.now() })
}

function ToastContainer() {
  const [toasts, setToasts] = useState([])
  useEffect(() => {
    _toastListener = (toast) => {
      setToasts(prev => [...prev, toast])
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== toast.id)), 3200)
    }
    return () => { _toastListener = null }
  }, [])
  if (!toasts.length) return null
  return (
    <div style={{ position: 'fixed', bottom: 24, right: 24, zIndex: 9999, display: 'flex', flexDirection: 'column', gap: 8 }}>
      {toasts.map(t => (
        <div key={t.id} style={{
          background: t.type === 'error' ? '#fef2f2' : t.type === 'warning' ? '#fffbeb' : '#f0fdf4',
          border: `1px solid ${t.type === 'error' ? '#fecaca' : t.type === 'warning' ? '#fde68a' : '#bbf7d0'}`,
          color: t.type === 'error' ? S.error : t.type === 'warning' ? S.warning : S.success,
          padding: '12px 18px', borderRadius: 10, fontSize: 13, fontWeight: 600,
          fontFamily: 'var(--font-body)', boxShadow: '0 8px 24px rgba(0,0,0,0.1)',
          animation: 'toastIn 0.25s ease-out', maxWidth: 360,
        }}>
          {t.type === 'error' ? '✕ ' : t.type === 'warning' ? '⚠ ' : '✓ '}{t.message}
        </div>
      ))}
    </div>
  )
}

