function Walkthrough({ onClose, onNavigate }) {
  const [step, setStep] = useState(0)
  const current = WALKTHROUGH_STEPS[step]
  const isLast = step === WALKTHROUGH_STEPS.length - 1

  const noteColors = ['#FFF9C4', '#FFECB3', '#FFF8E1', '#FFF3E0', '#E8F5E9', '#F3E5F5', '#E1F5FE', '#FFF9C4', '#FFECB3']
  const noteRotations = [-1.5, 1, -0.5, 1.2, -1, 0.8, -1.3, 0.5, -0.8]
  const bgColor = noteColors[step % noteColors.length]
  const rotation = noteRotations[step % noteRotations.length]

  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 1000, pointerEvents: 'none' }}>
      <div style={{ position: 'absolute', inset: 0, background: 'rgba(26,18,53,0.45)', backdropFilter: 'blur(2px)', pointerEvents: 'all' }} onClick={onClose} />
      <div style={{ position: 'absolute', left: 12, top: current.top - 4, width: S.sidebar.width - 24, height: 36, borderRadius: 8, background: 'rgba(124,92,252,0.35)', boxShadow: '0 0 20px rgba(124,92,252,0.5)', pointerEvents: 'none', transition: 'top 0.4s cubic-bezier(0.4, 0, 0.2, 1)', zIndex: 1001 }} />
      <div style={{
        position: 'absolute', left: S.sidebar.width + 16,
        top: Math.min(current.top - 20, typeof window !== 'undefined' && window.innerHeight ? window.innerHeight - 280 : 400),
        width: 320, pointerEvents: 'all', zIndex: 1002,
        transition: 'top 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
      }}>
        <div style={{ position: 'absolute', left: -8, top: 28, width: 0, height: 0, borderTop: '8px solid transparent', borderBottom: '8px solid transparent', borderRight: `8px solid ${bgColor}`, filter: 'drop-shadow(-2px 0 2px rgba(0,0,0,0.08))' }} />
        <div style={{
          background: bgColor, borderRadius: 4, padding: '24px 22px 20px',
          transform: `rotate(${rotation}deg)`,
          boxShadow: '0 6px 20px rgba(0,0,0,0.12), 0 2px 6px rgba(0,0,0,0.08), 2px 2px 0 rgba(0,0,0,0.03)',
          border: '1px solid rgba(0,0,0,0.06)', position: 'relative',
        }}>
          <div style={{ position: 'absolute', top: -6, left: '50%', transform: 'translateX(-50%) rotate(0.5deg)', width: 60, height: 12, background: 'rgba(255,255,255,0.6)', borderRadius: 2, border: '1px solid rgba(0,0,0,0.04)' }} />
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
            <span style={{ fontFamily: "'Caveat', cursive", fontSize: 14, color: 'rgba(0,0,0,0.35)', fontWeight: 700 }}>{step + 1} of {WALKTHROUGH_STEPS.length}</span>
            <button onClick={onClose} style={{ background: 'none', border: 'none', color: 'rgba(0,0,0,0.25)', cursor: 'pointer', padding: 2 }}><X size={14} /></button>
          </div>
          <h3 style={{ fontFamily: "'Caveat', cursive", fontSize: 26, fontWeight: 700, color: '#1a1235', marginBottom: 8, lineHeight: 1.1 }}>{current.title}</h3>
          <p style={{ fontFamily: "'Sora', sans-serif", fontSize: 13, color: '#4a4162', lineHeight: 1.6, marginBottom: 18, fontWeight: 400 }}>{current.desc}</p>
          <div style={{ display: 'flex', gap: 4, marginBottom: 14 }}>
            {WALKTHROUGH_STEPS.map((_, i) => (
              <div key={i} style={{ width: i === step ? 18 : 5, height: 5, borderRadius: 3, background: i <= step ? '#7C5CFC' : 'rgba(0,0,0,0.12)', transition: 'all 0.3s' }} />
            ))}
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <button onClick={onClose} style={{ background: 'none', border: 'none', fontFamily: "'Sora', sans-serif", fontSize: 12, color: 'rgba(0,0,0,0.3)', cursor: 'pointer', fontWeight: 500 }}>skip tour</button>
            <div style={{ display: 'flex', gap: 8 }}>
              {step > 0 && (
                <button onClick={() => { setStep(step - 1); onNavigate(WALKTHROUGH_STEPS[step - 1].id) }} style={{ padding: '6px 14px', borderRadius: 6, border: '1px solid rgba(0,0,0,0.12)', background: 'rgba(255,255,255,0.5)', color: '#4a4162', fontSize: 12, fontWeight: 600, cursor: 'pointer', fontFamily: "'Sora', sans-serif" }}>Back</button>
              )}
              {isLast ? (
                <button onClick={onClose} style={{ padding: '6px 16px', borderRadius: 6, border: 'none', background: '#1a1235', color: '#fff', fontSize: 12, fontWeight: 600, cursor: 'pointer', fontFamily: "'Sora', sans-serif" }}>Let&apos;s go! 🚀</button>
              ) : (
                <button onClick={() => { setStep(step + 1); onNavigate(WALKTHROUGH_STEPS[step + 1].id) }} style={{ padding: '6px 16px', borderRadius: 6, border: 'none', background: '#1a1235', color: '#fff', fontSize: 12, fontWeight: 600, cursor: 'pointer', fontFamily: "'Sora', sans-serif", display: 'flex', alignItems: 'center', gap: 4 }}>Next <ChevronRight size={13} /></button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

/* ═══════════ DASHBOARD — CLICKABLE CARDS + GUIDED EMPTY STATE ═══════════ */

function Dashboard({ userId, workspaceId, onNavigate }) {
  const [stats, setStats] = useState({ requests: 0, reps: 0, todos: 0 })
  const [topRequests, setTopRequests] = useState([])
  const [rampReps, setRampReps] = useState([])
  const [loading, setLoading] = useState(true)
  useEffect(() => {
    if (!workspaceId) return
    async function load() {
      const [{ count: reqCount },{ count: repCount },{ count: todoCount },{ data: requestsData },{ data: repsData }] = await Promise.all([
        supabase.from('requests').select('*', { count: 'exact', head: true }).eq('workspace_id', workspaceId).eq('status', 'open'),
        supabase.from('reps').select('*', { count: 'exact', head: true }).eq('workspace_id', workspaceId),
        supabase.from('todos').select('*', { count: 'exact', head: true }).eq('workspace_id', workspaceId).eq('user_id', userId).eq('done', false),
        supabase.from('requests').select('id, title, priority_score').eq('workspace_id', workspaceId).eq('status', 'open').order('priority_score', { ascending: false }).limit(3),
        supabase.from('reps').select('id, name, progress').eq('workspace_id', workspaceId).limit(4),
      ])
      setStats({ requests: reqCount || 0, reps: repCount || 0, todos: todoCount || 0 })
      setTopRequests(requestsData || [])
      setRampReps(repsData || [])
      setLoading(false)
    }
    load()
  }, [userId, workspaceId])
  const calcPct = (rep) => { if (!rep?.progress?.sections) return 0; const all = Object.values(rep.progress.sections).flat(); return Math.round((all.filter(Boolean).length / all.length) * 100) }
  const avgRamp = rampReps.length ? `${Math.round(rampReps.reduce((a, r) => a + calcPct(r), 0) / rampReps.length)}%` : '—'

  const statCards = [
    { label: 'Open Requests', value: stats.requests, icon: Inbox, color: S.primary, target: 'intake' },
    { label: 'Ramping Reps', value: stats.reps, icon: Users, color: S.success, target: 'ramp' },
    { label: 'Must-Do Tasks', value: stats.todos, icon: Target, color: S.warning, target: 'planning' },
    { label: 'Avg Ramp %', value: avgRamp, icon: TrendingUp, color: '#8b5cf6', target: 'ramp' },
  ]

  const isEmpty = !loading && stats.requests === 0 && stats.reps === 0 && stats.todos === 0

  return (
    <div>
      <div style={{ marginBottom: 32 }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 30, fontWeight: 700, color: S.ink, marginBottom: 6, letterSpacing: '-0.5px' }}>{new Date().getHours() < 12 ? 'Good morning' : new Date().getHours() < 17 ? 'Good afternoon' : 'Good evening'} 👋</h1>
        <p style={{ color: S.inkSecondary, fontSize: 15, fontWeight: 300 }}>Here&apos;s what&apos;s happening — {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}</p>
      </div>
      {loading ? <Loader size={20} style={{ animation: 'spin 1s linear infinite' }} /> : (
        <>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16, marginBottom: 24 }}>
            {statCards.map(s => (<Card key={s.label} onClick={() => onNavigate(s.target)} style={{ borderTop: `3px solid ${s.color}22`, cursor: 'pointer' }}><div style={{ width: 38, height: 38, borderRadius: 10, background: s.color + '15', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: 14 }}><s.icon size={18} color={s.color} /></div><div style={{ fontSize: 30, fontWeight: 700, color: S.ink, fontFamily: 'var(--font-display)', marginBottom: 4, letterSpacing: '-0.5px' }}>{s.value}</div><div style={{ fontSize: 13, color: S.muted }}>{s.label}</div></Card>))}
          </div>

          {isEmpty ? (
            <Card style={{ padding: '48px 24px', textAlign: 'center' }}>
              <div style={{ width: 64, height: 64, borderRadius: 16, background: `linear-gradient(135deg, ${S.accentBg2}, ${S.accentBg})`, display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 20px' }}>
                <Users size={30} color={S.primary} />
              </div>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: 20, fontWeight: 700, color: S.ink, marginBottom: 8, letterSpacing: '-0.3px' }}>Your workspace is ready</h3>
              <p style={{ fontSize: 14, color: S.muted, lineHeight: 1.65, maxWidth: 420, margin: '0 auto 24px' }}>Add your first rep to start tracking onboarding, take 1:1 notes, and see this dashboard come alive.</p>
              <div style={{ display: 'flex', gap: 10, justifyContent: 'center' }}>
                <Btn onClick={() => onNavigate('ramp')}><Plus size={16} />Add your first rep</Btn>
                <Btn variant="ghost" onClick={() => onNavigate('intake')}>Create a request</Btn>
              </div>
            </Card>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
              <Card><h3 style={{ fontWeight: 700, color: S.ink, marginBottom: 16, fontFamily: 'var(--font-display)', fontSize: 16, letterSpacing: '-0.2px' }}>Priority Queue</h3>{topRequests.length === 0 ? <div style={{ fontSize: 13, color: S.muted, padding: '8px 0' }}>No open requests — <span style={{ color: S.primary, cursor: 'pointer', fontWeight: 600 }} onClick={() => onNavigate('intake')}>add one in Intake</span>.</div> : <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>{topRequests.map((r, i) => (<div key={r.id} onClick={() => onNavigate('intake')} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '10px 12px', background: S.accentBg, borderRadius: 9, cursor: 'pointer', transition: 'background 0.15s' }} onMouseEnter={e => e.currentTarget.style.background = S.accentBg2} onMouseLeave={e => e.currentTarget.style.background = S.accentBg}><div style={{ width: 6, height: 6, borderRadius: '50%', background: i === 0 ? S.error : i === 1 ? S.warning : S.primary, flexShrink: 0 }} /><span style={{ flex: 1, fontSize: 13, color: S.inkSecondary }}>{r.title}</span><span style={{ fontSize: 11, fontWeight: 700, color: S.primary }}>P{r.priority_score}</span></div>))}</div>}</Card>
              <Card><h3 style={{ fontWeight: 700, color: S.ink, marginBottom: 16, fontFamily: 'var(--font-display)', fontSize: 16, letterSpacing: '-0.2px' }}>Ramp Snapshot</h3>{rampReps.length === 0 ? <div style={{ fontSize: 13, color: S.muted, padding: '8px 0' }}>No reps yet — <span style={{ color: S.primary, cursor: 'pointer', fontWeight: 600 }} onClick={() => onNavigate('ramp')}>add one in Ramp</span>.</div> : rampReps.map(r => { const pct = calcPct(r); return (<div key={r.id} style={{ marginBottom: 14 }}><div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}><span style={{ fontSize: 13, fontWeight: 600, color: S.ink }}>{r.name}</span><span style={{ fontSize: 13, color: S.primary, fontWeight: 700 }}>{pct}%</span></div><div style={{ height: 6, background: S.borderLight, borderRadius: 3 }}><div style={{ height: '100%', width: `${pct}%`, background: `linear-gradient(90deg, ${S.primary}, ${S.primaryHover})`, borderRadius: 3 }} /></div></div>) })}</Card>
            </div>
          )}
        </>
      )}
    </div>
  )
}

/* ═══════════ INTAKE — SHARE LABEL + PRIORITY TOOLTIP + EMPTY STATE ═══════════ */

function Intake({ userId, workspaceId }) { const [requests, setRequests] = useState([]); const [showModal, setShowModal] = useState(false); const [filter, setFilter] = useState('all'); const [form, setForm] = useState({ title: '', bucket: 'Collateral', description: '', impact: 3, urgency: 3, effort: 3, status: 'open' }); const load = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('requests').select('*').eq('workspace_id', workspaceId).order('created_at', { ascending: false }); if (error) { handleDbError(error, 'load requests'); return; } setRequests(data || []); }, [workspaceId]); useEffect(() => { load() }, [load]); const save = async () => { const priority = Math.round((form.impact * form.urgency) / form.effort); const { error } = await supabase.from('requests').insert({ ...form, user_id: userId, workspace_id: workspaceId, priority_score: priority }); if (!handleDbError(error, 'add request')) return; showToast('Request added'); setShowModal(false); setForm({ title: '', bucket: 'Collateral', description: '', impact: 3, urgency: 3, effort: 3, status: 'open' }); load(); }; const updateStatus = async (id, status) => { const { error } = await supabase.from('requests').update({ status }).eq('id', id); if (!handleDbError(error, 'update request')) return; showToast('Status updated'); load(); }; const buckets = ['all', 'Collateral', 'Training Session', 'Everboarding', 'Onboarding', 'Process', 'Playbook', 'Other']; const filtered = filter === 'all' ? requests : requests.filter(r => r.bucket === filter); const statusColor = { open: 'purple', 'in-progress': 'yellow', done: 'green' }; return (<div><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}><div><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>Intake</h1><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>Manage and prioritize enablement requests</p></div><div style={{ display: 'flex', gap: 8, alignItems: 'center' }}><button title="Copy public intake form link" onClick={() => { const link = `${window.location.origin}/intake-form`; navigator.clipboard.writeText(link).then(() => showToast('Intake form link copied!')) }} style={{ display: 'inline-flex', alignItems: 'center', gap: 6, padding: '8px 14px', borderRadius: 8, border: `1px solid ${S.border}`, background: 'transparent', cursor: 'pointer', color: S.inkSecondary, transition: 'all 0.15s', fontSize: 13, fontWeight: 600, fontFamily: 'var(--font-body)' }} onMouseEnter={e => { e.currentTarget.style.background = S.accentBg; e.currentTarget.style.borderColor = S.primary; e.currentTarget.style.color = S.primary }} onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.borderColor = S.border; e.currentTarget.style.color = S.inkSecondary }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg>Share form</button><Btn onClick={() => setShowModal(true)}><Plus size={16} />New Request</Btn></div></div><div style={{ display: 'flex', gap: 8, marginBottom: 20, flexWrap: 'wrap' }}>{buckets.map(b => <button key={b} onClick={() => setFilter(b)} style={{ padding: '6px 14px', borderRadius: 100, border: `1px solid ${filter === b ? S.primary : S.border}`, background: filter === b ? S.accentBg2 : 'transparent', color: filter === b ? S.primary : S.inkSecondary, fontSize: 13, fontWeight: 600, cursor: 'pointer', fontFamily: 'var(--font-body)', transition: 'all 0.15s' }}>{b === 'all' ? 'All' : b}</button>)}</div><div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>{filtered.length === 0 && <EmptyState icon={Inbox} title="No requests yet" description="Share your intake form with the team so they can submit requests — no login needed." actionLabel="Create a request" onAction={() => setShowModal(true)} />}{filtered.map(r => (<Card key={r.id} style={{ padding: '16px 20px' }}><div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between' }}><div style={{ flex: 1 }}><div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 6 }}><span style={{ fontWeight: 700, color: S.ink, fontSize: 15 }}>{r.title}</span><Badge color={statusColor[r.status] || 'gray'}>{r.status}</Badge><Badge color="gray">{r.bucket}</Badge></div>{r.description && <p style={{ color: S.muted, fontSize: 13, marginBottom: 8 }}>{r.description}</p>}<div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>{r.created_at && <span style={{ fontSize: 11, color: S.border }}>{new Date(r.created_at).toLocaleDateString()}</span>}<span style={{ fontSize: 12, color: S.muted }}>Impact: <b style={{ color: S.inkSecondary }}>{r.impact}</b></span><span style={{ fontSize: 12, color: S.muted }}>Urgency: <b style={{ color: S.inkSecondary }}>{r.urgency}</b></span><span style={{ fontSize: 12, color: S.muted }}>Effort: <b style={{ color: S.inkSecondary }}>{r.effort}</b></span><Tooltip text="Scored as Impact × Urgency ÷ Effort"><span style={{ fontSize: 12, color: S.primary, fontWeight: 700, cursor: 'help', display: 'inline-flex', alignItems: 'center', gap: 3 }}>Priority: {r.priority_score} <Info size={11} /></span></Tooltip></div></div><div style={{ display: 'flex', gap: 6, marginLeft: 16 }}>{r.status !== 'done' && <Btn size="sm" variant="ghost" onClick={() => updateStatus(r.id, r.status === 'open' ? 'in-progress' : 'done')}>{r.status === 'open' ? 'Start' : 'Done'}</Btn>}<Btn size="sm" variant="danger" onClick={async () => { if (!confirm('Delete this request?')) return; const { error } = await supabase.from('requests').delete().eq('id', r.id); if (!handleDbError(error, 'delete request')) return; showToast('Request deleted'); load(); }}><Trash2 size={12} /></Btn></div></div></Card>))}</div>{showModal && (<Modal title="New Enablement Request" onClose={() => setShowModal(false)}><Field label="Title"><Input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="What's being requested?" /></Field><Field label="Bucket"><Select value={form.bucket} onChange={e => setForm({ ...form, bucket: e.target.value })}>{['Collateral', 'Training Session', 'Everboarding', 'Onboarding', 'Process', 'Playbook', 'Other'].map(b => <option key={b} value={b}>{b}</option>)}</Select></Field><Field label="Description"><Textarea value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} placeholder="More context..." /></Field>{[['impact', 'Impact'], ['urgency', 'Urgency'], ['effort', 'Effort']].map(([key, label]) => (<Field key={key} label={`${label}: ${form[key]}/5`}><input type="range" min={1} max={5} value={form[key]} onChange={e => setForm({ ...form, [key]: +e.target.value })} style={{ width: '100%', accentColor: S.primary }} /></Field>))}<div style={{ background: '#2a2445', borderRadius: 8, padding: '10px 14px', marginBottom: 16 }}><span style={{ fontSize: 12, color: S.muted }}>Auto-priority: </span><span style={{ fontSize: 14, fontWeight: 700, color: S.primaryLight }}>{Math.round((form.impact * form.urgency) / form.effort)}</span><span style={{ fontSize: 11, color: S.muted, marginLeft: 8 }}>(Impact × Urgency ÷ Effort)</span></div><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end', marginTop: 8 }}><Btn variant="ghost" onClick={() => setShowModal(false)}>Cancel</Btn><Btn onClick={save} disabled={!form.title}>Add Request</Btn></div></Modal>)}</div>); }

function Ramp({ userId, workspaceId }) { const [reps, setReps] = useState([]); const [selected, setSelected] = useState(null); const [showAddRep, setShowAddRep] = useState(false); const [newRepName, setNewRepName] = useState(''); const load = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('reps').select('*').eq('workspace_id', workspaceId); if (error) { handleDbError(error, 'load reps'); return; } setReps(data || []); if (data && data.length > 0 && !selected) setSelected(data[0]); }, [workspaceId, selected]); useEffect(() => { load() }, [load]); const addRep = async () => { if (!newRepName.trim()) return; const defaultProgress = { sections: { 'Company & Culture': [false,false,false,false], 'Sales Process': [false,false,false,false], 'Product Deep Dive': [false,false,false,false], 'Outbound Mastery': [false,false,false,false], 'Live Certification': [false,false,false,false] }, benchmarks: {} }; const { data, error } = await supabase.from('reps').insert({ user_id: userId, workspace_id: workspaceId, name: newRepName, progress: defaultProgress, start_date: new Date().toISOString() }).select().single(); if (!handleDbError(error, 'add rep')) return; showToast(`${newRepName} added — start checking off their onboarding`); setNewRepName(''); setShowAddRep(false); if (data) setSelected(data); load(); }; const deleteRep = async (rep) => { if (!confirm(`Delete ${rep.name}? This can't be undone.`)) return; const { error } = await supabase.from('reps').delete().eq('id', rep.id); if (!handleDbError(error, 'delete rep')) return; showToast(`${rep.name} removed`); if (selected?.id === rep.id) setSelected(null); load(); }; const toggleCheck = async (section, idx) => { if (!selected) return; const updated = { ...selected.progress }; updated.sections[section][idx] = !updated.sections[section][idx]; const { error } = await supabase.from('reps').update({ progress: updated }).eq('id', selected.id); if (!handleDbError(error, 'update progress')) return; setSelected({ ...selected, progress: updated }); load(); }; const sections = ['Company & Culture', 'Sales Process', 'Product Deep Dive', 'Outbound Mastery', 'Live Certification']; const sectionItems = { 'Company & Culture': ['Company history & mission', 'ICP and buyer personas', 'Competitive landscape', 'Internal tools & tech stack'], 'Sales Process': ['Discovery call framework', 'Demo flow walkthrough', 'Objection handling', 'Pipeline management'], 'Product Deep Dive': ['Core product features', 'Integration ecosystem', 'Pricing & packaging', 'Customer use cases'], 'Outbound Mastery': ['Cold email sequences', 'LinkedIn outreach', 'Cold call framework', 'Social selling tactics'], 'Live Certification': ['Discovery call roleplay', 'Demo certification', 'Objection handling test', 'Manager sign-off'] }; const calcPct = (rep) => { if (!rep?.progress?.sections) return 0; const all = Object.values(rep.progress.sections).flat(); return Math.round((all.filter(Boolean).length / all.length) * 100); }; return (<div style={{ display: 'flex', gap: 20, height: 'calc(100vh - 120px)' }}><div style={{ width: 220, background: '#fff', border: `1px solid ${S.borderLight}`, borderRadius: 14, padding: 16, overflowY: 'auto', flexShrink: 0 }}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}><span style={{ fontWeight: 700, fontSize: 13, color: S.ink }}>Reps</span><button onClick={() => setShowAddRep(true)} style={{ background: 'none', border: 'none', color: S.primary, cursor: 'pointer' }}><Plus size={16} /></button></div>{reps.map(r => (<div key={r.id} style={{ padding: '10px 12px', borderRadius: 9, marginBottom: 4, background: selected?.id === r.id ? S.accentBg2 : 'transparent', border: `1px solid ${selected?.id === r.id ? S.primary + '40' : 'transparent'}`, position: 'relative' }}><div onClick={() => setSelected(r)} style={{ cursor: 'pointer' }}><div style={{ fontWeight: 600, fontSize: 13, color: S.ink, paddingRight: 18, marginBottom: 6, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{r.name}</div><div style={{ display: 'flex', alignItems: 'center', gap: 6 }}><div style={{ flex: 1, height: 4, background: S.borderLight, borderRadius: 2 }}><div style={{ height: '100%', width: `${calcPct(r)}%`, background: `linear-gradient(90deg, ${S.primary}, ${S.primaryHover})`, borderRadius: 2 }} /></div><span style={{ fontSize: 11, color: S.primary, fontWeight: 700 }}>{calcPct(r)}%</span></div></div><button onClick={e => { e.stopPropagation(); deleteRep(r) }} style={{ position: 'absolute', top: 8, right: 8, background: 'none', border: 'none', color: S.muted, cursor: 'pointer', opacity: 0.4, padding: 2, borderRadius: 4 }} onMouseEnter={e => { e.currentTarget.style.opacity = 1; e.currentTarget.style.color = S.error }} onMouseLeave={e => { e.currentTarget.style.opacity = 0.4; e.currentTarget.style.color = S.muted }}><Trash2 size={12} /></button></div>))}{reps.length === 0 && <div style={{ fontSize: 13, color: S.muted, textAlign: 'center', paddingTop: 20, lineHeight: 1.6 }}>No reps yet.<br/><span style={{ color: S.primary, cursor: 'pointer', fontWeight: 600 }} onClick={() => setShowAddRep(true)}>Add your first rep →</span></div>}</div><div style={{ flex: 1, overflowY: 'auto' }}>{!selected ? (<div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>{reps.length === 0 ? <EmptyState icon={Users} title="Add your first rep" description="Once you add a rep, you'll see their onboarding checklist here — 5 sections, 20 checkboxes, full progress tracking." actionLabel="Add rep" onAction={() => setShowAddRep(true)} /> : <div style={{ color: S.muted }}>Select a rep to view their onboarding</div>}</div>) : (<><div style={{ marginBottom: 24 }}><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>{selected.name}</h1><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>{calcPct(selected)}% complete · Started {selected.start_date ? new Date(selected.start_date).toLocaleDateString() : 'recently'}</p></div><div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>{sections.map(section => { const checks = selected.progress?.sections?.[section] || [false,false,false,false]; const done = checks.filter(Boolean).length; return (<Card key={section}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}><h3 style={{ fontWeight: 700, fontSize: 15, color: S.ink, fontFamily: 'var(--font-display)', letterSpacing: '-0.2px' }}>{section}</h3><Badge color={done === 4 ? 'green' : 'gray'}>{done}/4</Badge></div><div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>{sectionItems[section].map((item, i) => (<div key={i} onClick={() => toggleCheck(section, i)} style={{ display: 'flex', alignItems: 'center', gap: 10, cursor: 'pointer', padding: '6px 8px', borderRadius: 7, transition: 'background 0.15s' }} onMouseEnter={e => e.currentTarget.style.background = S.accentBg} onMouseLeave={e => e.currentTarget.style.background = 'transparent'}><div style={{ width: 18, height: 18, borderRadius: 5, border: `2px solid ${checks[i] ? S.primary : S.border}`, background: checks[i] ? S.primary : 'transparent', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, transition: 'all 0.15s' }}>{checks[i] && <Check size={11} color="#fff" strokeWidth={3} />}</div><span style={{ fontSize: 14, color: checks[i] ? S.muted : S.inkSecondary, textDecoration: checks[i] ? 'line-through' : 'none' }}>{item}</span></div>))}</div></Card>); })}</div></>)}</div>{showAddRep && (<Modal title="Add Rep" onClose={() => setShowAddRep(false)}><Field label="Name"><Input value={newRepName} onChange={e => setNewRepName(e.target.value)} placeholder="Rep's name" /></Field><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}><Btn variant="ghost" onClick={() => setShowAddRep(false)}>Cancel</Btn><Btn onClick={addRep} disabled={!newRepName.trim()}>Add Rep</Btn></div></Modal>)}</div>); }

/* ═══════════ 1:1 NOTES — "ONLY YOU CAN SEE THIS" LABEL ═══════════ */

function Notes({ userId, workspaceId }) { const [reps, setReps] = useState([]); const [selectedRep, setSelectedRep] = useState(null); const [notes, setNotes] = useState([]); const [showModal, setShowModal] = useState(false); const [showAddRep, setShowAddRep] = useState(false); const [newRepName, setNewRepName] = useState(''); const [form, setForm] = useState({ shared_agenda: '', private_notes: '' }); const [analyzing, setAnalyzing] = useState(false); const [aiResult, setAiResult] = useState(null); const loadReps = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('reps').select('*').eq('workspace_id', workspaceId); if (error) { handleDbError(error, 'load reps'); return; } setReps(data || []); if (data && data.length > 0 && !selectedRep) setSelectedRep(data[0]); }, [workspaceId, selectedRep]); useEffect(() => { loadReps() }, [loadReps]); useEffect(() => { if (!selectedRep || !workspaceId) return; supabase.from('notes').select('*').eq('workspace_id', workspaceId).eq('user_id', userId).eq('rep_id', selectedRep.id).order('created_at', { ascending: false }).then(({ data, error }) => { if (error) { handleDbError(error, 'load notes'); return; } setNotes(data || []); }); }, [selectedRep, userId, workspaceId]); const addRepInline = async () => { if (!newRepName.trim()) return; const defaultProgress = { sections: { 'Company & Culture': [false,false,false,false], 'Sales Process': [false,false,false,false], 'Product Deep Dive': [false,false,false,false], 'Outbound Mastery': [false,false,false,false], 'Live Certification': [false,false,false,false] }, benchmarks: {} }; const { data, error } = await supabase.from('reps').insert({ user_id: userId, workspace_id: workspaceId, name: newRepName, progress: defaultProgress, start_date: new Date().toISOString() }).select().single(); if (!handleDbError(error, 'add rep')) return; showToast(`${newRepName} added`); setNewRepName(''); setShowAddRep(false); if (data) setSelectedRep(data); loadReps(); }; const save = async () => { const { error } = await supabase.from('notes').insert({ ...form, user_id: userId, workspace_id: workspaceId, rep_id: selectedRep.id, date: new Date().toISOString(), sentiment: aiResult?.sentiment || null, ai_action: aiResult?.action || null }); if (!handleDbError(error, 'save note')) return; showToast('Note saved'); setShowModal(false); setForm({ shared_agenda: '', private_notes: '' }); setAiResult(null); supabase.from('notes').select('*').eq('workspace_id', workspaceId).eq('user_id', userId).eq('rep_id', selectedRep.id).order('created_at', { ascending: false }).then(({ data }) => setNotes(data || [])); }; const analyze = async () => { if (!form.private_notes && !form.shared_agenda) return; setAnalyzing(true); try { const res = await fetch('https://api.anthropic.com/v1/messages', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 1000, messages: [{ role: 'user', content: `Analyze this 1:1 note from a sales enablement manager. Return ONLY a JSON object with: sentiment ("positive"|"neutral"|"concern"), action (1 suggested next action as string), theme (1-2 word tag), session (suggested session topic).\nShared agenda: ${form.shared_agenda}\nPrivate notes: ${form.private_notes}` }] }) }); const data = await res.json(); const text = data.content?.[0]?.text || '{}'; setAiResult(JSON.parse(text.replace(/```json|```/g, '').trim())); } catch { setAiResult({ sentiment: 'neutral', action: 'Follow up next session', theme: 'General', session: 'Discovery practice' }); } setAnalyzing(false); }; const sentimentColor = { positive: 'green', neutral: 'gray', concern: 'red' }; return (<div style={{ display: 'flex', gap: 20, height: 'calc(100vh - 120px)' }}><div style={{ width: 200, background: '#fff', border: `1px solid ${S.borderLight}`, borderRadius: 14, padding: 16, overflowY: 'auto', flexShrink: 0 }}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}><span style={{ fontWeight: 700, fontSize: 13, color: S.ink }}>Reps</span><button onClick={() => setShowAddRep(true)} style={{ background: 'none', border: 'none', color: S.primary, cursor: 'pointer' }}><Plus size={16} /></button></div>{reps.map(r => (<div key={r.id} onClick={() => setSelectedRep(r)} style={{ padding: '10px 12px', borderRadius: 9, marginBottom: 4, cursor: 'pointer', background: selectedRep?.id === r.id ? S.accentBg2 : 'transparent', border: `1px solid ${selectedRep?.id === r.id ? S.primary + '40' : 'transparent'}`, transition: 'all 0.15s' }}><span style={{ fontWeight: 600, fontSize: 13, color: S.ink }}>{r.name}</span></div>))}{reps.length === 0 && <div style={{ fontSize: 12, color: S.muted, lineHeight: 1.6, padding: '4px 0' }}>No reps yet — tap + above.</div>}</div><div style={{ flex: 1, overflowY: 'auto' }}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}><div><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>1:1 Notes</h1><div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 4 }}><p style={{ color: S.muted, fontSize: 14 }}>{selectedRep ? `Notes for ${selectedRep.name}` : 'Select a rep'}</p><span style={{ fontSize: 11, fontWeight: 700, padding: '2px 8px', borderRadius: 100, background: '#fef3c7', color: S.warning }}>🔒 Private to you</span></div></div>{selectedRep && <Btn onClick={() => setShowModal(true)}><Plus size={16} />Add Note</Btn>}</div><div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>{notes.map(n => (<Card key={n.id}><div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12 }}><span style={{ fontSize: 13, color: S.muted }}>{new Date(n.date).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}</span>{n.sentiment && <Badge color={sentimentColor[n.sentiment] || 'gray'}>{n.sentiment}</Badge>}</div>{n.shared_agenda && <div style={{ marginBottom: 10 }}><div style={{ fontSize: 12, fontWeight: 700, color: S.muted, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 4 }}>Shared Agenda</div><p style={{ fontSize: 14, color: S.inkSecondary }}>{n.shared_agenda}</p></div>}{n.ai_action && <div style={{ marginTop: 12, padding: '10px 14px', background: S.accentBg, borderRadius: 9, borderLeft: `3px solid ${S.primary}` }}><div style={{ fontSize: 12, fontWeight: 700, color: S.primary, marginBottom: 4 }}>✦ AI Suggestion</div><p style={{ fontSize: 13, color: S.inkSecondary }}>{n.ai_action}</p></div>}</Card>))}{notes.length === 0 && selectedRep && <EmptyState icon={MessageSquare} title={`No notes yet for ${selectedRep.name}`} description="After your next 1:1, add a note here. The AI will analyze sentiment and suggest next steps." actionLabel="Add note" onAction={() => setShowModal(true)} />}{!selectedRep && reps.length === 0 && <EmptyState icon={MessageSquare} title="Add a rep to start" description="Once you have reps in the system, you can write private coaching notes for each one." />}</div></div>{showAddRep && (<Modal title="Add Rep" onClose={() => setShowAddRep(false)}><Field label="Name"><Input value={newRepName} onChange={e => setNewRepName(e.target.value)} placeholder="Rep's name" /></Field><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}><Btn variant="ghost" onClick={() => setShowAddRep(false)}>Cancel</Btn><Btn onClick={addRepInline} disabled={!newRepName.trim()}>Add Rep</Btn></div></Modal>)}{showModal && (<Modal title={`New 1:1 Note — ${selectedRep?.name}`} onClose={() => { setShowModal(false); setAiResult(null) }} wide><Field label="Shared Agenda" hint="(rep can see this)"><Textarea value={form.shared_agenda} onChange={e => setForm({ ...form, shared_agenda: e.target.value })} placeholder="Topics to cover together..." /></Field><Field label="Private Notes" hint="🔒 Only you can see this"><Textarea value={form.private_notes} onChange={e => setForm({ ...form, private_notes: e.target.value })} placeholder="Your private observations, concerns, coaching notes..." rows={4} /></Field>{!aiResult ? (<Btn variant="ghost" onClick={analyze} disabled={analyzing} style={{ marginBottom: 16, color: S.primary, borderColor: S.primary }}>{analyzing ? <><Loader size={14} style={{ animation: 'spin 1s linear infinite' }} />Analyzing...</> : <><Sparkles size={14} />Analyze with AI</>}</Btn>) : (<div style={{ background: '#2a2445', borderRadius: 10, padding: 16, marginBottom: 16, border: '1px solid rgba(155,126,255,0.2)' }}><div style={{ fontSize: 12, fontWeight: 700, color: S.primaryLight, marginBottom: 10, display: 'flex', alignItems: 'center', gap: 6 }}><Sparkles size={12} />AI Analysis</div><div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}><div><div style={{ fontSize: 11, color: S.muted, marginBottom: 3 }}>Sentiment</div><Badge color={sentimentColor[aiResult.sentiment] || 'gray'}>{aiResult.sentiment}</Badge></div><div><div style={{ fontSize: 11, color: S.muted, marginBottom: 3 }}>Theme</div><span style={{ fontSize: 13, color: '#fff', fontWeight: 600 }}>{aiResult.theme}</span></div><div style={{ gridColumn: '1/-1' }}><div style={{ fontSize: 11, color: S.muted, marginBottom: 3 }}>Suggested Action</div><p style={{ fontSize: 13, color: '#ddd' }}>{aiResult.action}</p></div><div style={{ gridColumn: '1/-1' }}><div style={{ fontSize: 11, color: S.muted, marginBottom: 3 }}>Session Idea</div><p style={{ fontSize: 13, color: S.primaryLight }}>{aiResult.session}</p></div></div></div>)}<div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}><Btn variant="ghost" onClick={() => { setShowModal(false); setAiResult(null) }}>Cancel</Btn><Btn onClick={save}>Save Note</Btn></div></Modal>)}</div>); }

/* ═══════════ COLLATERALS — TOAST + EMPTY STATE ═══════════ */

function Collaterals({ userId, workspaceId }) { const [items, setItems] = useState([]); const [showModal, setShowModal] = useState(false); const [search, setSearch] = useState(''); const [form, setForm] = useState({ title: '', bucket: 'Battle Card', description: '', link: '' }); const load = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('collaterals').select('*').eq('workspace_id', workspaceId).order('created_at', { ascending: false }); if (error) { handleDbError(error, 'load collaterals'); return; } setItems(data || []); }, [workspaceId]); useEffect(() => { load() }, [load]); const save = async () => { const { error } = await supabase.from('collaterals').insert({ ...form, user_id: userId, workspace_id: workspaceId, usage_count: 0 }); if (!handleDbError(error, 'add collateral')) return; showToast('Asset added'); setShowModal(false); setForm({ title: '', bucket: 'Battle Card', description: '', link: '' }); load(); }; const bump = async (id, count) => { const { error } = await supabase.from('collaterals').update({ usage_count: count + 1 }).eq('id', id); if (!handleDbError(error, 'update collateral')) return; showToast('Usage logged'); load(); }; const filtered = items.filter(i => i.title?.toLowerCase().includes(search.toLowerCase())); const bucketColors = { 'Battle Card': 'red', 'Framework': 'purple', 'One-Pager': 'green', 'Template': 'yellow', 'Guide': 'gray', 'Sequence': 'purple', 'Other': 'gray' }; return (<div><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}><div><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>Collaterals</h1><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>Your enablement asset library</p></div><div style={{ display: 'flex', gap: 10 }}><input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search assets..." style={{ padding: '9px 14px', border: `1px solid ${S.border}`, borderRadius: 9, fontSize: 13, fontFamily: 'var(--font-body)', outline: 'none', color: S.ink, background: '#fff', transition: 'border-color 0.15s' }} onFocus={e => e.target.style.borderColor = S.primary} onBlur={e => e.target.style.borderColor = S.border} /><Btn onClick={() => setShowModal(true)}><Plus size={16} />Add Asset</Btn></div></div><div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 16 }}>{filtered.map(item => (<Card key={item.id}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}><Badge color={bucketColors[item.bucket] || 'gray'}>{item.bucket}</Badge><span style={{ fontSize: 12, color: S.muted }}>{item.usage_count || 0} uses</span></div><h3 style={{ fontWeight: 700, fontSize: 15, color: S.ink, marginBottom: 6, fontFamily: 'var(--font-display)', letterSpacing: '-0.2px' }}>{item.title}</h3>{item.description && <p style={{ fontSize: 13, color: S.muted, marginBottom: 12 }}>{item.description}</p>}<div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: item.description ? 0 : 12 }}>{item.link ? <a href={item.link} target="_blank" rel="noopener noreferrer" style={{ fontSize: 13, color: S.primary, textDecoration: 'none', fontWeight: 600 }}>Open →</a> : <span />}<Btn size="sm" variant="ghost" onClick={() => bump(item.id, item.usage_count || 0)}>+1 Use</Btn><Btn size="sm" variant="danger" onClick={async (e) => { e.stopPropagation(); if (!confirm('Delete this asset?')) return; const { error } = await supabase.from('collaterals').delete().eq('id', item.id); if (!handleDbError(error, 'delete collateral')) return; showToast('Asset deleted'); load(); }} style={{ marginLeft: 4 }}><Trash2 size={12} /></Btn></div></Card>))}{filtered.length === 0 && items.length === 0 && <div style={{ gridColumn: '1/-1' }}><EmptyState icon={BookOpen} title="No assets yet" description="Add battle cards, playbooks, one-pagers, and templates. Paste a Drive or Notion link — track how often each one gets used." actionLabel="Add your first asset" onAction={() => setShowModal(true)} /></div>}{filtered.length === 0 && items.length > 0 && <div style={{ color: S.muted, gridColumn: '1/-1', textAlign: 'center', padding: 48 }}>No assets match &quot;{search}&quot;</div>}</div>{showModal && (<Modal title="Add Collateral" onClose={() => setShowModal(false)}><Field label="Title"><Input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="Asset name" /></Field><Field label="Type"><Select value={form.bucket} onChange={e => setForm({ ...form, bucket: e.target.value })}>{['Battle Card', 'Framework', 'One-Pager', 'Template', 'Guide', 'Sequence', 'Other'].map(b => <option key={b}>{b}</option>)}</Select></Field><Field label="Description"><Textarea value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} placeholder="What's this asset for?" rows={2} /></Field><Field label="Link" hint="(paste a Drive, Notion, or any URL)"><Input value={form.link} onChange={e => setForm({ ...form, link: e.target.value })} placeholder="https://..." /></Field><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}><Btn variant="ghost" onClick={() => setShowModal(false)}>Cancel</Btn><Btn onClick={save} disabled={!form.title}>Add Asset</Btn></div></Modal>)}</div>); }

/* ═══════════ SESSIONS — TOAST + EMPTY STATE ═══════════ */

function Sessions({ userId, workspaceId }) { const [sessions, setSessions] = useState([]); const [showModal, setShowModal] = useState(false); const [form, setForm] = useState({ title: '', date: '', type: 'Training', attendees: '' }); const load = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('sessions').select('*').eq('workspace_id', workspaceId).order('date', { ascending: true }); if (error) { handleDbError(error, 'load sessions'); return; } setSessions(data || []); }, [workspaceId]); useEffect(() => { load() }, [load]); const save = async () => { const { error } = await supabase.from('sessions').insert({ ...form, user_id: userId, workspace_id: workspaceId, completed: false, date: form.date || null }); if (!handleDbError(error, 'schedule session')) return; showToast('Session scheduled'); setShowModal(false); setForm({ title: '', date: '', type: 'Training', attendees: '' }); load(); }; const markDone = async (id) => { const { error } = await supabase.from('sessions').update({ completed: true }).eq('id', id); if (!handleDbError(error, 'mark session done')) return; showToast('Session completed'); load(); }; const upcoming = sessions.filter(s => !s.completed); const completed = sessions.filter(s => s.completed); const typeColor = { Training: 'purple', Workshop: 'green', Coaching: 'yellow', Certification: 'red', Other: 'gray' }; return (<div><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}><div><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>Sessions</h1><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>Schedule and track training sessions</p></div><Btn onClick={() => setShowModal(true)}><Plus size={16} />Schedule Session</Btn></div>{sessions.length === 0 ? (<EmptyState icon={Video} title="No sessions yet" description="Schedule training sessions, workshops, and certifications. Track what's been delivered and what's coming up." actionLabel="Schedule your first session" onAction={() => setShowModal(true)} />) : (<><h3 style={{ fontWeight: 700, fontSize: 14, color: S.ink, marginBottom: 12 }}>Upcoming ({upcoming.length})</h3><div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 28 }}>{upcoming.map(s => (<Card key={s.id} style={{ padding: '14px 18px' }}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}><div><div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 4 }}><span style={{ fontWeight: 700, fontSize: 15, color: S.ink }}>{s.title}</span><Badge color={typeColor[s.type] || 'gray'}>{s.type}</Badge></div><div style={{ display: 'flex', gap: 16, fontSize: 13, color: S.muted }}>{s.date && <span>📅 {new Date(s.date).toLocaleDateString()}</span>}{s.attendees && <span>👥 {s.attendees}</span>}</div></div><Btn size="sm" onClick={() => markDone(s.id)}>Mark Done</Btn><Btn size="sm" variant="danger" onClick={async () => { if (!confirm('Delete this session?')) return; const { error } = await supabase.from('sessions').delete().eq('id', s.id); if (!handleDbError(error, 'delete session')) return; showToast('Session deleted'); load(); }} style={{ marginLeft: 4 }}><Trash2 size={12} /></Btn></div></Card>))}{upcoming.length === 0 && <div style={{ color: S.muted, fontSize: 14, padding: '12px 0' }}>No upcoming sessions. Schedule one!</div>}</div><h3 style={{ fontWeight: 700, fontSize: 14, color: S.ink, marginBottom: 12 }}>Completed ({completed.length})</h3><div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>{completed.map(s => (<Card key={s.id} style={{ padding: '14px 18px', opacity: 0.65 }}><div style={{ display: 'flex', alignItems: 'center', gap: 8 }}><Check size={16} color={S.success} /><span style={{ fontWeight: 600, fontSize: 14, color: S.ink, textDecoration: 'line-through' }}>{s.title}</span><Badge color={typeColor[s.type] || 'gray'}>{s.type}</Badge></div></Card>))}</div></>)}{showModal && (<Modal title="Schedule Session" onClose={() => setShowModal(false)}><Field label="Title"><Input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="Session name" /></Field><Field label="Date"><Input type="date" value={form.date} onChange={e => setForm({ ...form, date: e.target.value })} /></Field><Field label="Type"><Select value={form.type} onChange={e => setForm({ ...form, type: e.target.value })}>{['Training', 'Workshop', 'Coaching', 'Certification', 'Other'].map(t => <option key={t}>{t}</option>)}</Select></Field><Field label="Attendees"><Input value={form.attendees} onChange={e => setForm({ ...form, attendees: e.target.value })} placeholder="Who's joining?" /></Field><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}><Btn variant="ghost" onClick={() => setShowModal(false)}>Cancel</Btn><Btn onClick={save} disabled={!form.title}>Schedule</Btn></div></Modal>)}</div>); }

/* ═══════════ PULSE CHECKS, WEEKLY PLANNING, FORECASTING, LEADERBOARDS ═══════════ */
/* (identical to original except success toasts added to saves) */

const COACHING_AREAS = [{ key: 'emails', label: 'Cold Emails', icon: '📧', desc: 'Prospecting quality, personalization, reply rate' },{ key: 'calls', label: 'Cold Calls', icon: '📞', desc: 'Talk track, objection handling, qualification' },{ key: 'demos', label: 'Demos', icon: '🖥', desc: 'Discovery, presentation, deal advancement' },{ key: 'negotiations', label: 'Negotiations', icon: '🤝', desc: 'Pricing, multi-threading, closing conversations' }]
const scoreColor = (n) => { if (n >= 4) return { color: S.success, bg: '#d1fae5' }; if (n >= 3) return { color: S.warning, bg: '#fef3c7' }; return { color: S.error, bg: '#fee2e2' }; }
const nowPeriod = () => { const d = new Date(); return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}` }

function PulseChecks({ userId, workspaceId }) { const [tab, setTab] = useState('surveys'); const [pulses, setPulses] = useState([]); const [selected, setSelected] = useState(null); const [showCreate, setShowCreate] = useState(false); const [form, setForm] = useState({ title: '', questions: [{ text: '', type: 'rating', options: [] }] }); const loadPulses = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('pulse_checks').select('*').eq('workspace_id', workspaceId).order('created_at', { ascending: false }); if (error) { handleDbError(error, 'load pulse checks'); return; } setPulses(data || []); }, [workspaceId]); useEffect(() => { loadPulses() }, [loadPulses]); const addQuestion = () => setForm({ ...form, questions: [...form.questions, { text: '', type: 'rating', options: [] }] }); const removeQuestion = (i) => setForm({ ...form, questions: form.questions.filter((_, j) => j !== i) }); const updateQuestion = (i, field, value) => { const qs = [...form.questions]; qs[i] = { ...qs[i], [field]: value }; if (field === 'type' && value === 'choice' && !qs[i].options?.length) qs[i].options = ['', '']; setForm({ ...form, questions: qs }); }; const addOption = (qi) => { const qs = [...form.questions]; qs[qi] = { ...qs[qi], options: [...(qs[qi].options || []), ''] }; setForm({ ...form, questions: qs }); }; const updateOption = (qi, oi, val) => { const qs = [...form.questions]; const opts = [...(qs[qi].options || [])]; opts[oi] = val; qs[qi] = { ...qs[qi], options: opts }; setForm({ ...form, questions: qs }); }; const removeOption = (qi, oi) => { const qs = [...form.questions]; qs[qi] = { ...qs[qi], options: qs[qi].options.filter((_, k) => k !== oi) }; setForm({ ...form, questions: qs }); }; const savePulse = async () => { const { error } = await supabase.from('pulse_checks').insert({ user_id: userId, workspace_id: workspaceId, title: form.title, questions: form.questions.filter(q => q.text.trim()), responses: [] }); if (!handleDbError(error, 'create pulse check')) return; showToast('Pulse check created'); setShowCreate(false); setForm({ title: '', questions: [{ text: '', type: 'rating', options: [] }] }); loadPulses(); }; const [reps, setReps] = useState([]); const [selectedRep, setSelectedRep] = useState(null); const [coachPeriod, setCoachPeriod] = useState(nowPeriod()); const [coachForm, setCoachForm] = useState({ emails: 3, calls: 3, demos: 3, negotiations: 3, notes: '' }); const [showCoachModal, setShowCoachModal] = useState(false); const [savingCoach, setSavingCoach] = useState(false); const loadReps = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('reps').select('*').eq('workspace_id', workspaceId); if (error) { handleDbError(error, 'load reps'); return; } setReps(data || []); if (data?.length && !selectedRep) setSelectedRep(data[0]); }, [workspaceId, selectedRep]); useEffect(() => { if (tab === 'coaching') loadReps() }, [tab, loadReps]); const openCoachModal = () => { const existing = selectedRep?.progress?.benchmarks?.[coachPeriod]; setCoachForm(existing ? { emails: existing.emails, calls: existing.calls, demos: existing.demos, negotiations: existing.negotiations, notes: existing.notes || '' } : { emails: 3, calls: 3, demos: 3, negotiations: 3, notes: '' }); setShowCoachModal(true); }; const saveCoach = async () => { if (!selectedRep) return; setSavingCoach(true); const updated = { ...selectedRep.progress, benchmarks: { ...(selectedRep.progress?.benchmarks || {}), [coachPeriod]: { ...coachForm, date: new Date().toISOString() } } }; const { error } = await supabase.from('reps').update({ progress: updated }).eq('id', selectedRep.id); if (!handleDbError(error, 'save coaching score')) { setSavingCoach(false); return; } showToast('Coaching score saved'); setSelectedRep({ ...selectedRep, progress: updated }); setShowCoachModal(false); setSavingCoach(false); loadReps(); }; const currentScore = selectedRep?.progress?.benchmarks?.[coachPeriod]; const allPeriods = selectedRep?.progress?.benchmarks ? Object.entries(selectedRep.progress.benchmarks).sort((a, b) => b[0].localeCompare(a[0])) : []; const typeLabel = { rating: '⭐ Rating 1–5', choice: '☑ Multiple choice', text: '📝 Free text' }; return (<div><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}><div><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>Pulse Checks</h1><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>Surveys and coaching scores for your team</p></div><div style={{ display: 'flex', gap: 8 }}>{tab === 'surveys' && <Btn onClick={() => setShowCreate(true)}><Plus size={16} />Create Pulse</Btn>}{tab === 'coaching' && selectedRep && <Btn onClick={openCoachModal}><Plus size={16} />Add Score</Btn>}</div></div><div style={{ display: 'flex', gap: 4, marginBottom: 24, background: S.accentBg, borderRadius: 10, padding: 4, width: 'fit-content' }}>{[{ id: 'surveys', label: '📋 Surveys' }, { id: 'coaching', label: '🎯 Coaching Scores' }].map(t => (<button key={t.id} onClick={() => setTab(t.id)} style={{ padding: '8px 18px', borderRadius: 8, border: 'none', cursor: 'pointer', fontFamily: 'var(--font-body)', fontWeight: 600, fontSize: 13, background: tab === t.id ? '#fff' : 'transparent', color: tab === t.id ? S.ink : S.muted, boxShadow: tab === t.id ? '0 1px 6px rgba(26,18,53,0.1)' : 'none', transition: 'all 0.15s' }}>{t.label}</button>))}</div>{tab === 'surveys' && (<>{pulses.length === 0 ? (<Card style={{ padding: 48, textAlign: 'center' }}><div style={{ width: 56, height: 56, borderRadius: 14, background: S.accentBg2, display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px' }}><Activity size={26} color={S.primary} /></div><h3 style={{ fontFamily: 'var(--font-display)', fontSize: 18, fontWeight: 700, color: S.ink, marginBottom: 8, letterSpacing: '-0.2px' }}>What&apos;s a Pulse Check?</h3><p style={{ fontSize: 14, color: S.inkSecondary, lineHeight: 1.65, maxWidth: 480, margin: '0 auto 20px' }}>A lightweight survey you send your reps. Mix rating scales, multiple choice, and free text questions.</p><Btn onClick={() => setShowCreate(true)}><Plus size={16} />Create your first pulse</Btn></Card>) : (<div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 16 }}>{pulses.map(p => (<Card key={p.id} onClick={() => setSelected(p)}><div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 10 }}><span style={{ fontWeight: 700, fontSize: 15, color: S.ink, fontFamily: 'var(--font-display)', letterSpacing: '-0.2px' }}>{p.title}</span><Badge color="purple">{p.questions?.length || 0} Qs</Badge></div><div style={{ fontSize: 12, color: S.muted }}>{new Date(p.created_at).toLocaleDateString()}</div></Card>))}</div>)}</>)}{tab === 'coaching' && (<div style={{ display: 'flex', gap: 20, minHeight: 400 }}><div style={{ width: 200, background: '#fff', border: `1px solid ${S.borderLight}`, borderRadius: 14, padding: 16, flexShrink: 0 }}><div style={{ fontWeight: 700, fontSize: 13, color: S.ink, marginBottom: 14 }}>Reps</div>{reps.map(r => (<div key={r.id} onClick={() => setSelectedRep(r)} style={{ padding: '10px 12px', borderRadius: 9, marginBottom: 4, cursor: 'pointer', background: selectedRep?.id === r.id ? S.accentBg2 : 'transparent', border: `1px solid ${selectedRep?.id === r.id ? S.primary + '40' : 'transparent'}`, transition: 'all 0.15s' }}><span style={{ fontWeight: 600, fontSize: 13, color: S.ink }}>{r.name}</span></div>))}{reps.length === 0 && <div style={{ fontSize: 13, color: S.muted, lineHeight: 1.5 }}>Add reps in Ramp &amp; Onboarding first</div>}</div><div style={{ flex: 1 }}>{!selectedRep ? <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', color: S.muted }}>Select a rep to view coaching scores</div> : (<><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}><div><h2 style={{ fontFamily: 'var(--font-display)', fontSize: 20, fontWeight: 700, color: S.ink, letterSpacing: '-0.3px' }}>{selectedRep.name}</h2><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>Monthly coaching scores</p></div><input type="month" value={coachPeriod} onChange={e => setCoachPeriod(e.target.value)} style={{ padding: '8px 12px', border: `1px solid ${S.border}`, borderRadius: 8, fontSize: 13, fontFamily: 'var(--font-body)', outline: 'none', color: S.ink, background: '#fff', cursor: 'pointer' }} /></div><div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12, marginBottom: 24 }}>{COACHING_AREAS.map(area => { const score = currentScore?.[area.key]; const sc = score ? scoreColor(score) : { color: S.muted, bg: S.borderLight }; return (<Card key={area.key} style={{ padding: '18px 16px', textAlign: 'center' }}><div style={{ fontSize: 24, marginBottom: 6 }}>{area.icon}</div><div style={{ fontWeight: 700, fontSize: 13, color: S.ink, marginBottom: 4 }}>{area.label}</div><div style={{ fontSize: 11, color: S.muted, marginBottom: 12, lineHeight: 1.4 }}>{area.desc}</div>{score ? <div style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: 44, height: 44, borderRadius: '50%', background: sc.bg, color: sc.color, fontWeight: 700, fontSize: 20, fontFamily: 'var(--font-display)' }}>{score}</div> : <div style={{ fontSize: 12, color: S.muted, fontStyle: 'italic' }}>Not scored</div>}</Card>); })}</div>{currentScore?.notes && (<Card style={{ marginBottom: 24, borderLeft: `4px solid ${S.primary}`, paddingLeft: 20 }}><div style={{ fontSize: 12, fontWeight: 700, color: S.primary, marginBottom: 6, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Coaching notes · {coachPeriod}</div><p style={{ fontSize: 14, color: S.inkSecondary, lineHeight: 1.65 }}>{currentScore.notes}</p></Card>)}{allPeriods.length > 0 && (<Card><div style={{ fontWeight: 700, fontSize: 15, color: S.ink, marginBottom: 16, fontFamily: 'var(--font-display)', letterSpacing: '-0.2px' }}>Score history</div><div style={{ overflowX: 'auto' }}><table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}><thead><tr><th style={{ textAlign: 'left', color: S.muted, fontWeight: 600, padding: '0 12px 12px 0', fontSize: 12 }}>Period</th>{COACHING_AREAS.map(a => <th key={a.key} style={{ textAlign: 'center', color: S.muted, fontWeight: 600, padding: '0 12px 12px', fontSize: 12 }}>{a.icon} {a.label}</th>)}</tr></thead><tbody>{allPeriods.map(([period, data]) => (<tr key={period} style={{ borderTop: `1px solid ${S.borderLight}` }}><td style={{ padding: '10px 12px 10px 0', fontWeight: 600, color: S.ink }}>{period}</td>{COACHING_AREAS.map(a => { const sc = data[a.key] ? scoreColor(data[a.key]) : null; return <td key={a.key} style={{ textAlign: 'center', padding: '10px 12px' }}>{data[a.key] ? <span style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: 28, height: 28, borderRadius: '50%', background: sc.bg, color: sc.color, fontWeight: 700, fontSize: 13 }}>{data[a.key]}</span> : <span style={{ color: S.borderLight }}>—</span>}</td>; })}</tr>))}</tbody></table></div></Card>)}{allPeriods.length === 0 && !currentScore && <div style={{ textAlign: 'center', color: S.muted, padding: 48 }}>No coaching scores yet. Use &quot;Add Score&quot; above.</div>}</>)}</div></div>)}{selected && (<Modal title={selected.title} onClose={() => setSelected(null)} wide>{(selected.questions || []).map((q, i) => { const isObj = typeof q === 'object' && q !== null; const text = isObj ? q.text : q; const type = isObj ? q.type : 'rating'; const options = isObj ? (q.options || []) : []; return (<div key={i} style={{ marginBottom: 20, padding: '14px 16px', background: '#2a2445', borderRadius: 10 }}><div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 10 }}><div style={{ color: '#fff', fontWeight: 600, fontSize: 14 }}>{i + 1}. {text}</div><span style={{ fontSize: 11, color: S.muted, background: '#3a3550', padding: '3px 8px', borderRadius: 100 }}>{typeLabel[type]}</span></div>{type === 'rating' && <div style={{ display: 'flex', gap: 6 }}>{[1,2,3,4,5].map(n => <div key={n} style={{ flex: 1, height: 8, background: '#3a3550', borderRadius: 4 }} />)}<span style={{ fontSize: 11, color: S.muted, marginLeft: 8, whiteSpace: 'nowrap' }}>1 → 5</span></div>}{type === 'choice' && options.length > 0 && <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>{options.map((opt, j) => opt && <div key={j} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '6px 10px', background: '#3a3550', borderRadius: 6 }}><div style={{ width: 14, height: 14, borderRadius: 3, border: '2px solid rgba(255,255,255,0.2)', flexShrink: 0 }} /><span style={{ fontSize: 13, color: '#ddd' }}>{opt}</span></div>)}</div>}{type === 'text' && <div style={{ background: '#3a3550', borderRadius: 6, padding: '8px 12px', fontSize: 13, color: S.muted, fontStyle: 'italic' }}>Open text response...</div>}</div>); })}<div style={{ color: S.muted, fontSize: 13, marginTop: 8 }}>Share this pulse check link with your team to collect responses.</div></Modal>)}{showCreate && (<Modal title="Create Pulse Check" onClose={() => setShowCreate(false)} wide><Field label="Title"><Input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="e.g. Week 3 Readiness Check" /></Field><Field label="Questions">{form.questions.map((q, i) => (<div key={i} style={{ background: '#2a2445', borderRadius: 10, padding: 14, marginBottom: 10 }}><div style={{ display: 'flex', gap: 8, marginBottom: q.type === 'choice' ? 12 : 0 }}><Input value={q.text} onChange={e => updateQuestion(i, 'text', e.target.value)} placeholder={`Question ${i + 1}`} style={{ flex: 1 }} /><select value={q.type} onChange={e => updateQuestion(i, 'type', e.target.value)} style={{ background: '#3a3550', border: '1px solid rgba(155,126,255,0.15)', borderRadius: 8, padding: '10px 12px', color: '#fff', fontSize: 13, fontFamily: 'var(--font-body)', outline: 'none', cursor: 'pointer', flexShrink: 0 }}><option value="rating">⭐ Rating 1–5</option><option value="choice">☑ Multiple choice</option><option value="text">📝 Free text</option></select>{form.questions.length > 1 && <button onClick={() => removeQuestion(i)} style={{ background: 'none', border: 'none', color: S.muted, cursor: 'pointer', padding: 4 }}><X size={16} /></button>}</div>{q.type === 'choice' && (<div>{(q.options || []).map((opt, j) => (<div key={j} style={{ display: 'flex', gap: 6, marginBottom: 6 }}><Input value={opt} onChange={e => updateOption(i, j, e.target.value)} placeholder={`Option ${j + 1}`} />{q.options.length > 2 && <button onClick={() => removeOption(i, j)} style={{ background: 'none', border: 'none', color: S.muted, cursor: 'pointer' }}><X size={14} /></button>}</div>))}<Btn size="sm" variant="ghost" onClick={() => addOption(i)} style={{ marginTop: 2 }}><Plus size={13} />Add option</Btn></div>)}</div>))}<Btn size="sm" variant="ghost" onClick={addQuestion} style={{ marginTop: 4 }}><Plus size={14} />Add Question</Btn></Field><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end', marginTop: 8 }}><Btn variant="ghost" onClick={() => setShowCreate(false)}>Cancel</Btn><Btn onClick={savePulse} disabled={!form.title}>Create</Btn></div></Modal>)}{showCoachModal && selectedRep && (<Modal title={`Coaching Score — ${selectedRep.name}`} onClose={() => setShowCoachModal(false)} wide><div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 20, padding: '10px 14px', background: '#2a2445', borderRadius: 9 }}><span style={{ fontSize: 13, color: S.muted }}>Period:</span><input type="month" value={coachPeriod} onChange={e => setCoachPeriod(e.target.value)} style={{ background: 'transparent', border: 'none', color: '#fff', fontSize: 14, fontWeight: 700, fontFamily: 'var(--font-body)', outline: 'none', cursor: 'pointer' }} /></div><div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14, marginBottom: 16 }}>{COACHING_AREAS.map(area => (<div key={area.key} style={{ background: '#2a2445', borderRadius: 10, padding: 16 }}><div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}><span style={{ fontSize: 20 }}>{area.icon}</span><div><div style={{ fontWeight: 700, color: '#fff', fontSize: 13 }}>{area.label}</div><div style={{ fontSize: 11, color: S.muted }}>{area.desc}</div></div></div><div style={{ display: 'flex', gap: 6 }}>{[1,2,3,4,5].map(n => { const active = coachForm[area.key] >= n; const sc = scoreColor(coachForm[area.key]); return <button key={n} onClick={() => setCoachForm({ ...coachForm, [area.key]: n })} style={{ flex: 1, height: 38, borderRadius: 7, border: 'none', cursor: 'pointer', background: active ? sc.bg : '#3a3550', color: active ? sc.color : S.muted, fontWeight: 700, fontSize: 14, transition: 'all 0.15s' }}>{n}</button>; })}</div></div>))}</div><Field label="Coaching notes"><Textarea value={coachForm.notes} onChange={e => setCoachForm({ ...coachForm, notes: e.target.value })} placeholder="What's working well? What to improve?" rows={3} /></Field><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}><Btn variant="ghost" onClick={() => setShowCoachModal(false)}>Cancel</Btn><Btn onClick={saveCoach} disabled={savingCoach}>{savingCoach ? 'Saving...' : 'Save Score'}</Btn></div></Modal>)}</div>); }

function WeeklyPlanning({ userId, workspaceId }) { const [todos, setTodos] = useState([]); const [adding, setAdding] = useState(null); const [newTask, setNewTask] = useState(''); const load = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('todos').select('*').eq('workspace_id', workspaceId).eq('user_id', userId).order('created_at', { ascending: true }); if (error) { handleDbError(error, 'load tasks'); return; } setTodos(data || []); }, [workspaceId, userId]); useEffect(() => { load() }, [load]); const addTask = async (bucket) => { if (!newTask.trim()) return; const { error } = await supabase.from('todos').insert({ user_id: userId, workspace_id: workspaceId, title: newTask, bucket, done: false }); if (!handleDbError(error, 'add task')) return; showToast('Task added'); setNewTask(''); setAdding(null); load(); }; const toggle = async (id, done) => { const { error } = await supabase.from('todos').update({ done: !done }).eq('id', id); if (!handleDbError(error, 'update task')) return; load(); }; const del = async (id) => { const { error } = await supabase.from('todos').delete().eq('id', id); if (!handleDbError(error, 'delete task')) return; load(); }; const buckets = [{ key: 'must', label: 'Must Do', color: S.error, bg: '#fff5f5' },{ key: 'should', label: 'Should Do', color: S.warning, bg: '#fffbeb' },{ key: 'could', label: 'Could Do', color: S.primary, bg: S.accentBg }]; const total = todos.length; const done = todos.filter(t => t.done).length; return (<div><div style={{ marginBottom: 24 }}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, marginBottom: 8, letterSpacing: '-0.4px' }}>Weekly Planning</h1><Btn variant="ghost" size="sm" onClick={async () => { if (!confirm('Archive completed tasks and start a fresh week?')) return; const doneIds = todos.filter(t => t.done).map(t => t.id); if (doneIds.length === 0) { showToast('No completed tasks to archive', 'warning'); return; } for (const id of doneIds) { await supabase.from('todos').delete().eq('id', id); } showToast(`${doneIds.length} completed tasks archived`); load(); }}>🔄 New Week</Btn></div><div style={{ display: 'flex', alignItems: 'center', gap: 12 }}><div style={{ flex: 1, maxWidth: 280, height: 6, background: S.borderLight, borderRadius: 3 }}><div style={{ height: '100%', width: `${total ? (done / total) * 100 : 0}%`, background: `linear-gradient(90deg, ${S.primary}, ${S.primaryHover})`, borderRadius: 3, transition: 'width 0.3s' }} /></div><span style={{ fontSize: 13, color: S.muted }}>{done}/{total} complete</span></div></div><div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16 }}>{buckets.map(b => { const items = todos.filter(t => t.bucket === b.key); return (<div key={b.key} style={{ background: b.bg, border: `1px solid ${b.color}18`, borderRadius: 14, padding: 16 }}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}><span style={{ fontWeight: 700, fontSize: 14, color: b.color, fontFamily: 'var(--font-display)', letterSpacing: '-0.1px' }}>{b.label}</span><button onClick={() => setAdding(b.key)} style={{ background: 'none', border: 'none', color: b.color, cursor: 'pointer' }}><Plus size={16} /></button></div><div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>{items.map(t => (<div key={t.id} style={{ background: '#fff', borderRadius: 9, padding: '10px 12px', display: 'flex', alignItems: 'center', gap: 8, border: `1px solid ${S.borderLight}` }}><div onClick={() => toggle(t.id, t.done)} style={{ width: 18, height: 18, borderRadius: 5, border: `2px solid ${t.done ? b.color : S.border}`, background: t.done ? b.color : 'transparent', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', flexShrink: 0, transition: 'all 0.15s' }}>{t.done && <Check size={11} color="#fff" strokeWidth={3} />}</div><span style={{ flex: 1, fontSize: 13, color: t.done ? S.muted : S.ink, textDecoration: t.done ? 'line-through' : 'none' }}>{t.title}</span><button onClick={() => del(t.id)} style={{ background: 'none', border: 'none', color: S.muted, cursor: 'pointer', opacity: 0.4 }}><X size={12} /></button></div>))}{adding === b.key && (<div style={{ background: '#fff', borderRadius: 9, padding: '8px 12px', border: `1px solid ${b.color}` }}><input autoFocus value={newTask} onChange={e => setNewTask(e.target.value)} onKeyDown={e => { if (e.key === 'Enter') addTask(b.key); if (e.key === 'Escape') setAdding(null) }} placeholder="Add task..." style={{ width: '100%', border: 'none', outline: 'none', fontSize: 13, fontFamily: 'var(--font-body)', color: S.ink }} /></div>)}</div></div>); })}</div></div>); }

function Forecasting({ userId, workspaceId }) { const [items, setItems] = useState([]); const [showModal, setShowModal] = useState(false); const [form, setForm] = useState({ title: '', status: 'planned', impact: 'medium', eta: '', notes: '' }); const [dragId, setDragId] = useState(null); const [dragOver, setDragOver] = useState(null); const load = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('forecast').select('*').eq('workspace_id', workspaceId).order('created_at', { ascending: false }); if (error) { handleDbError(error, 'load forecast'); return; } setItems(data || []); }, [workspaceId]); useEffect(() => { load() }, [load]); const save = async () => { const { error } = await supabase.from('forecast').insert({ ...form, user_id: userId, workspace_id: workspaceId, eta: form.eta || null }); if (!handleDbError(error, 'add project')) return; showToast('Project added'); setShowModal(false); setForm({ title: '', status: 'planned', impact: 'medium', eta: '', notes: '' }); load(); }; const updateStatus = async (id, status) => { setItems(prev => prev.map(i => i.id === id ? { ...i, status } : i)); const { error } = await supabase.from('forecast').update({ status }).eq('id', id); if (error) { handleDbError(error, 'update project'); load(); } }; const handleDrop = (e, stage) => { e.preventDefault(); if (dragId) updateStatus(dragId, stage); setDragId(null); setDragOver(null); }; const stages = ['backlog', 'planned', 'in-progress', 'done']; const stageLabels = { backlog: 'Backlog', planned: 'Planned', 'in-progress': 'In Progress', done: 'Done' }; const stageColors = { backlog: S.muted, planned: S.primary, 'in-progress': S.warning, done: S.success }; const impactColor = { critical: 'red', high: 'yellow', medium: 'purple', low: 'gray' }; return (<div><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}><div><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>Forecasting</h1><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>Drag cards between columns to move them</p></div><Btn onClick={() => setShowModal(true)}><Plus size={16} />Add Project</Btn></div><div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 14 }}>{stages.map(stage => { const stageItems = items.filter(i => i.status === stage); const isOver = dragOver === stage; return (<div key={stage} onDragOver={e => { e.preventDefault(); setDragOver(stage) }} onDragLeave={e => { if (!e.currentTarget.contains(e.relatedTarget)) setDragOver(null) }} onDrop={e => handleDrop(e, stage)} style={{ background: isOver ? 'rgba(124,92,252,0.06)' : S.accentBg, border: `2px dashed ${isOver ? S.primary : 'transparent'}`, borderRadius: 14, padding: 14, minHeight: 220, transition: 'all 0.15s' }}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}><div style={{ display: 'flex', alignItems: 'center', gap: 7 }}><div style={{ width: 8, height: 8, borderRadius: '50%', background: stageColors[stage] }} /><span style={{ fontWeight: 700, fontSize: 13, color: S.ink }}>{stageLabels[stage]}</span></div><span style={{ fontSize: 11, fontWeight: 700, color: S.muted, background: S.borderLight, padding: '2px 8px', borderRadius: 100 }}>{stageItems.length}</span></div><div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>{stageItems.map(item => (<div key={item.id} draggable onDragStart={e => { setDragId(item.id); e.dataTransfer.effectAllowed = 'move' }} onDragEnd={() => { setDragId(null); setDragOver(null) }} style={{ background: '#fff', borderRadius: 10, padding: '12px 14px', border: `1px solid ${S.borderLight}`, cursor: 'grab', opacity: dragId === item.id ? 0.35 : 1, transition: 'opacity 0.15s, box-shadow 0.15s', userSelect: 'none', boxShadow: '0 1px 3px rgba(0,0,0,0.05)' }} onMouseEnter={e => { if (dragId !== item.id) e.currentTarget.style.boxShadow = `0 4px 16px rgba(124,92,252,0.14)` }} onMouseLeave={e => { e.currentTarget.style.boxShadow = '0 1px 3px rgba(0,0,0,0.05)' }}><div style={{ fontWeight: 600, fontSize: 13, color: S.ink, marginBottom: 8 }}>{item.title}</div><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}><Badge color={impactColor[item.impact] || 'gray'}>{item.impact}</Badge>{item.eta && <span style={{ fontSize: 11, color: S.muted }}>{new Date(item.eta).toLocaleDateString()}</span>}</div>{item.notes && <div style={{ fontSize: 12, color: S.muted, marginTop: 8, lineHeight: 1.5 }}>{item.notes}</div>}</div>))}{isOver && stageItems.length === 0 && <div style={{ padding: '24px 0', textAlign: 'center', color: S.primary, fontSize: 13, fontWeight: 600, border: `1px dashed ${S.primary}50`, borderRadius: 9 }}>Drop here</div>}</div></div>); })}</div>{showModal && (<Modal title="Add Project" onClose={() => setShowModal(false)}><Field label="Title"><Input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="Project name" /></Field><Field label="Status"><Select value={form.status} onChange={e => setForm({ ...form, status: e.target.value })}>{stages.map(s => <option key={s} value={s}>{stageLabels[s]}</option>)}</Select></Field><Field label="Impact"><Select value={form.impact} onChange={e => setForm({ ...form, impact: e.target.value })}>{['critical', 'high', 'medium', 'low'].map(i => <option key={i}>{i}</option>)}</Select></Field><Field label="ETA"><Input type="date" value={form.eta} onChange={e => setForm({ ...form, eta: e.target.value })} /></Field><Field label="Notes"><Textarea value={form.notes} onChange={e => setForm({ ...form, notes: e.target.value })} placeholder="Additional context..." rows={2} /></Field><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}><Btn variant="ghost" onClick={() => setShowModal(false)}>Cancel</Btn><Btn onClick={save} disabled={!form.title}>Add</Btn></div></Modal>)}</div>); }

function Leaderboards({ userId, workspaceId }) { const [boards, setBoards] = useState([]); const [selected, setSelected] = useState(null); const [showCreate, setShowCreate] = useState(false); const [showEntry, setShowEntry] = useState(false); const [form, setForm] = useState({ title: '', type: 'weekly', metric: '' }); const [entry, setEntry] = useState({ name: '', value: '', unit: '' }); const load = useCallback(async () => { if (!workspaceId) return; const { data, error } = await supabase.from('leaderboards').select('*').eq('workspace_id', workspaceId).order('created_at', { ascending: false }); if (error) { handleDbError(error, 'load leaderboards'); return; } setBoards(data || []); }, [workspaceId]); useEffect(() => { load() }, [load]); const createBoard = async () => { const { error } = await supabase.from('leaderboards').insert({ ...form, user_id: userId, workspace_id: workspaceId, entries: [] }); if (!handleDbError(error, 'create leaderboard')) return; showToast('Leaderboard created'); setShowCreate(false); setForm({ title: '', type: 'weekly', metric: '' }); load(); }; const addEntry = async () => { const updated = [...(selected.entries || []), { ...entry, value: +entry.value }].sort((a, b) => b.value - a.value); const { error } = await supabase.from('leaderboards').update({ entries: updated }).eq('id', selected.id); if (!handleDbError(error, 'add entry')) return; showToast('Entry added'); setSelected({ ...selected, entries: updated }); setShowEntry(false); setEntry({ name: '', value: '', unit: '' }); load(); }; const medals = ['🥇', '🥈', '🥉']; return (<div><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}><div><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>Leaderboards</h1><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>Track and celebrate rep performance</p></div><Btn onClick={() => setShowCreate(true)}><Plus size={16} />Create Board</Btn></div><div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 16 }}>{boards.map(b => (<Card key={b.id} onClick={() => setSelected(b)}><div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12 }}><span style={{ fontWeight: 700, fontSize: 15, color: S.ink, fontFamily: 'var(--font-display)', letterSpacing: '-0.2px' }}>{b.title}</span><Badge color="purple">{b.type}</Badge></div><div style={{ fontSize: 13, color: S.muted, marginBottom: 12 }}>{b.metric}</div>{(b.entries || []).slice(0, 3).map((e, i) => { const max = b.entries[0]?.value || 1; return (<div key={i} style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}><span style={{ fontSize: 16 }}>{medals[i] || '·'}</span><span style={{ fontSize: 13, color: S.ink, fontWeight: 600, minWidth: 80 }}>{e.name}</span><div style={{ flex: 1, height: 6, background: S.borderLight, borderRadius: 3 }}><div style={{ height: '100%', width: `${(e.value / max) * 100}%`, background: `linear-gradient(90deg, ${S.primary}, ${S.primaryHover})`, borderRadius: 3 }} /></div><span style={{ fontSize: 12, color: S.primary, fontWeight: 700 }}>{e.value}{e.unit}</span></div>); })}</Card>))}{boards.length === 0 && <div style={{ gridColumn: '1/-1' }}><EmptyState icon={Trophy} title="No leaderboards yet" description="Create boards to track calls made, demos booked, or any metric worth celebrating." actionLabel="Create your first board" onAction={() => setShowCreate(true)} /></div>}</div>{selected && (<Modal title={selected.title} onClose={() => setSelected(null)} wide><div style={{ marginBottom: 16 }}>{(selected.entries || []).map((e, i) => { const max = selected.entries[0]?.value || 1; return (<div key={i} style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 10, padding: '8px 12px', background: i < 3 ? S.accentBg : 'transparent', borderRadius: 9 }}><span style={{ fontSize: 20, minWidth: 28 }}>{medals[i] || `#${i + 1}`}</span><span style={{ color: '#fff', fontWeight: 700, minWidth: 100 }}>{e.name}</span><div style={{ flex: 1, height: 8, background: '#3a3550', borderRadius: 4 }}><div style={{ height: '100%', width: `${(e.value / max) * 100}%`, background: `linear-gradient(90deg, ${S.primary}, ${S.primaryHover})`, borderRadius: 4 }} /></div><span style={{ color: S.primaryLight, fontWeight: 700 }}>{e.value}{e.unit}</span></div>); })}</div><Btn onClick={() => setShowEntry(true)}><Plus size={14} />Add Entry</Btn></Modal>)}{showCreate && (<Modal title="Create Leaderboard" onClose={() => setShowCreate(false)}><Field label="Title"><Input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="e.g. This Week's Top Callers" /></Field><Field label="Metric"><Input value={form.metric} onChange={e => setForm({ ...form, metric: e.target.value })} placeholder="e.g. Calls made, Demos booked" /></Field><Field label="Type"><Select value={form.type} onChange={e => setForm({ ...form, type: e.target.value })}>{['weekly', 'quarterly', 'ramp', 'collateral'].map(t => <option key={t}>{t}</option>)}</Select></Field><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}><Btn variant="ghost" onClick={() => setShowCreate(false)}>Cancel</Btn><Btn onClick={createBoard} disabled={!form.title}>Create</Btn></div></Modal>)}{showEntry && (<Modal title="Add Entry" onClose={() => setShowEntry(false)}><Field label="Rep Name"><Input value={entry.name} onChange={e => setEntry({ ...entry, name: e.target.value })} placeholder="Name" /></Field><Field label="Value"><Input type="number" value={entry.value} onChange={e => setEntry({ ...entry, value: e.target.value })} placeholder="Score or count" /></Field><Field label="Unit (optional)"><Input value={entry.unit} onChange={e => setEntry({ ...entry, unit: e.target.value })} placeholder="e.g. calls, %" /></Field><div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}><Btn variant="ghost" onClick={() => setShowEntry(false)}>Cancel</Btn><Btn onClick={addEntry} disabled={!entry.name || !entry.value}>Add</Btn></div></Modal>)}</div>); }

function SettingsPanel({ user, workspaceId, userRole, onSignOut, onReplayWalkthrough }) { const [members, setMembers] = useState([]); const [inviteEmail, setInviteEmail] = useState(''); const [inviteRole, setInviteRole] = useState('member'); const [inviteStatus, setInviteStatus] = useState(''); const [workspaceName, setWorkspaceName] = useState(''); useEffect(() => { if (!workspaceId) return; supabase.from('workspaces').select('name').eq('id', workspaceId).single().then(({ data }) => { if (data) setWorkspaceName(data.name) }); supabase.from('workspace_members').select('*').eq('workspace_id', workspaceId).then(({ data }) => { setMembers(data || []) }); }, [workspaceId]); const sendInvite = async () => { if (!inviteEmail.trim() || !inviteEmail.includes('@')) { setInviteStatus('error'); return; } if (members.find(m => m.invited_email?.toLowerCase() === inviteEmail.trim().toLowerCase())) { setInviteStatus('error'); return; } const { error } = await supabase.from('workspace_members').insert({ workspace_id: workspaceId, user_id: user.id, role: inviteRole, invited_email: inviteEmail.trim().toLowerCase() }); if (error) { setInviteStatus('error'); showToast('Could not send invite', 'error'); return; } setInviteEmail(''); setInviteRole('member'); setInviteStatus('sent'); showToast('Invite saved'); setTimeout(() => setInviteStatus(''), 3000); supabase.from('workspace_members').select('*').eq('workspace_id', workspaceId).then(({ data }) => setMembers(data || [])); }; const removeMember = async (id) => { await supabase.from('workspace_members').delete().eq('id', id); showToast('Member removed'); supabase.from('workspace_members').select('*').eq('workspace_id', workspaceId).then(({ data }) => setMembers(data || [])); }; return (<div><div style={{ marginBottom: 28 }}><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>Settings</h1><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>Manage your workspace and team</p></div><Card style={{ marginBottom: 16 }}><h3 style={{ fontWeight: 700, fontSize: 15, color: S.ink, marginBottom: 18, paddingBottom: 14, borderBottom: `1px solid ${S.borderLight}`, fontFamily: 'var(--font-display)', letterSpacing: '-0.2px' }}>Team Members</h3><div style={{ marginBottom: 20 }}>{members.map((m, i) => (<div key={i} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 0', borderBottom: `1px solid ${S.borderLight}` }}><div style={{ width: 34, height: 34, borderRadius: '50%', background: `linear-gradient(135deg, ${S.primary}, #a78bfa)`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}><span style={{ color: '#fff', fontSize: 13, fontWeight: 700 }}>{(m.invited_email || user.email)?.[0]?.toUpperCase()}</span></div><div style={{ flex: 1, minWidth: 0 }}><div style={{ fontSize: 13, fontWeight: 600, color: S.ink, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{m.user_id === user.id ? user.email : (m.invited_email || 'Team member')}{m.user_id === user.id && <span style={{ fontSize: 11, color: S.muted, fontWeight: 400 }}> (you)</span>}</div></div><div style={{ display: 'flex', alignItems: 'center', gap: 8, flexShrink: 0 }}><span style={{ fontSize: 11, fontWeight: 700, padding: '2px 8px', borderRadius: 100, textTransform: 'uppercase', background: m.role === 'admin' ? S.accentBg2 : S.borderLight, color: m.role === 'admin' ? S.primary : S.muted }}>{m.role}</span>{m.user_id !== user.id && userRole === 'admin' && (<button onClick={() => removeMember(m.id)} style={{ background: 'none', border: 'none', color: S.muted, cursor: 'pointer', fontSize: 18, lineHeight: 1 }} onMouseEnter={e => e.currentTarget.style.color = S.error} onMouseLeave={e => e.currentTarget.style.color = S.muted}>×</button>)}</div></div>))}</div>{userRole === 'admin' && (<div style={{ background: S.accentBg, borderRadius: 11, padding: 16 }}><div style={{ fontSize: 12, fontWeight: 700, color: S.inkSecondary, textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 12 }}>Invite someone</div><div style={{ display: 'flex', gap: 8, marginBottom: 10 }}><input value={inviteEmail} onChange={e => { setInviteEmail(e.target.value); setInviteStatus('') }} onKeyDown={e => e.key === 'Enter' && sendInvite()} placeholder="colleague@company.com" style={{ flex: 1, padding: '9px 12px', border: `1px solid ${inviteStatus === 'error' ? S.error : S.border}`, borderRadius: 8, fontSize: 13, fontFamily: 'var(--font-body)', outline: 'none', color: S.ink, background: '#fff', transition: 'border-color 0.15s' }} onFocus={e => e.target.style.borderColor = S.primary} onBlur={e => e.target.style.borderColor = inviteStatus === 'error' ? S.error : S.border} /><select value={inviteRole} onChange={e => setInviteRole(e.target.value)} style={{ padding: '9px 12px', border: `1px solid ${S.border}`, borderRadius: 8, fontSize: 13, fontFamily: 'var(--font-body)', outline: 'none', color: S.ink, background: '#fff', cursor: 'pointer' }}><option value="member">Member</option><option value="admin">Admin</option></select><Btn onClick={sendInvite}>Invite</Btn></div><div style={{ fontSize: 12, color: S.muted, lineHeight: 1.65 }}><strong>Admin</strong> — full access, can invite &amp; manage members.<br /><strong>Member</strong> — full features, cannot change settings.</div>{inviteStatus === 'sent' && <div style={{ marginTop: 10, padding: '8px 12px', background: '#d1fae5', borderRadius: 8, fontSize: 13, color: S.success, fontWeight: 600 }}>✓ Invite saved — they&apos;ll join when they sign up with that email.</div>}{inviteStatus === 'error' && <div style={{ marginTop: 10, padding: '8px 12px', background: '#fee2e2', borderRadius: 8, fontSize: 13, color: S.error, fontWeight: 600 }}>Enter a valid email that isn&apos;t already in the workspace.</div>}</div>)}</Card>{[{ title: 'Workspace', items: [{ label: 'Workspace Name', value: workspaceName }, { label: 'Account Email', value: user?.email }, { label: 'Your Role', value: userRole }] },{ title: 'Integrations', items: [{ label: 'CRM (Salesforce / HubSpot)', value: 'Coming soon', badge: 'soon' }, { label: 'Gong', value: 'Coming soon', badge: 'soon' }, { label: 'Slack', value: 'Coming soon', badge: 'soon' }, { label: 'Google Calendar', value: 'Coming soon', badge: 'soon' }] },{ title: 'Platform', items: [{ label: 'AI Engine', value: 'Claude Sonnet (Anthropic)' }, { label: 'Version', value: 'EnableOS 2.0' }] }].map(group => (<Card key={group.title} style={{ marginBottom: 16 }}><h3 style={{ fontWeight: 700, fontSize: 15, color: S.ink, marginBottom: 16, paddingBottom: 12, borderBottom: `1px solid ${S.borderLight}`, fontFamily: 'var(--font-display)', letterSpacing: '-0.2px' }}>{group.title}</h3>{group.items.map(item => (<div key={item.label} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 0', borderBottom: `1px solid ${S.borderLight}` }}><span style={{ fontSize: 14, color: S.inkSecondary }}>{item.label}</span><div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>{item.badge && <Badge color="gray">{item.badge}</Badge>}<span style={{ fontSize: 14, color: S.muted }}>{item.value}</span></div></div>))}</Card>))}<div style={{ display: 'flex', gap: 10, marginTop: 4 }}><button onClick={onReplayWalkthrough} style={{ display: 'inline-flex', alignItems: 'center', gap: 6, padding: '9px 16px', borderRadius: 8, border: `1px solid ${S.border}`, background: 'transparent', color: S.inkSecondary, fontSize: 13, fontWeight: 600, cursor: 'pointer', fontFamily: 'var(--font-body)', transition: 'all 0.15s' }} onMouseEnter={e => { e.currentTarget.style.borderColor = S.primary; e.currentTarget.style.color = S.primary }} onMouseLeave={e => { e.currentTarget.style.borderColor = S.border; e.currentTarget.style.color = S.inkSecondary }}><Sparkles size={14} />Replay Walkthrough</button><Btn variant="danger" onClick={onSignOut}><LogOut size={16} />Sign Out</Btn></div></div>); }

function FeatureRequests() { const [submitted, setSubmitted] = useState(false); const [voted, setVoted] = useState([]); const [votes, setVotes] = useState({ 0:34, 1:28, 2:22, 3:19, 4:17, 5:31, 6:14, 7:26 }); const [form, setForm] = useState({ title: '', description: '', category: 'Platform' }); const categories = ['Platform', 'Integrations', 'AI', 'Analytics', 'Other']; const existing = [{ title: 'Enablement ROI dashboard — which assets closed which deals', status: 'roadmap', category: 'Analytics' },{ title: 'Google Calendar integration', status: 'planned', category: 'Integrations' },{ title: 'Slack intake bot — submit requests from Slack', status: 'planned', category: 'Integrations' },{ title: 'Salesforce / HubSpot CRM sync', status: 'planned', category: 'Integrations' },{ title: 'Gong integration — pull call themes into 1:1 notes', status: 'considering', category: 'Integrations' },{ title: 'AI-generated onboarding plans per rep', status: 'considering', category: 'AI' },{ title: 'Multi-seat workspaces for larger teams', status: 'roadmap', category: 'Platform' },{ title: 'Public-facing hub for reps to self-serve assets', status: 'considering', category: 'Platform' }]; const statusStyle = { planned: { bg: '#dbeafe', color: '#1d4ed8', label: 'Planned' }, considering: { bg: S.accentBg2, color: S.primary, label: 'Considering' }, roadmap: { bg: '#d1fae5', color: '#065f46', label: 'On Roadmap' } }; const vote = (i) => { if (voted.includes(i)) return; setVoted([...voted, i]); setVotes({ ...votes, [i]: votes[i] + 1 }); }; return (<div><div style={{ marginBottom: 24 }}><h1 style={{ fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 700, color: S.ink, letterSpacing: '-0.4px' }}>Feature Requests</h1><p style={{ color: S.muted, fontSize: 14, marginTop: 2 }}>Vote on what we build next, or suggest something new</p></div><div style={{ display: 'grid', gridTemplateColumns: '1fr 360px', gap: 20 }}><div><h3 style={{ fontWeight: 700, fontSize: 14, color: S.ink, marginBottom: 14 }}>Top requests</h3><div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>{existing.map((f, i) => { const s = statusStyle[f.status]; const hasVoted = voted.includes(i); return (<Card key={i} style={{ padding: '14px 16px', display: 'flex', alignItems: 'center', gap: 14 }}><button onClick={() => vote(i)} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2, background: hasVoted ? S.accentBg2 : S.accentBg, border: `1px solid ${hasVoted ? S.primary : S.border}`, borderRadius: 9, padding: '7px 10px', cursor: hasVoted ? 'default' : 'pointer', minWidth: 48, transition: 'all 0.15s' }}><Star size={13} color={hasVoted ? S.primary : S.muted} fill={hasVoted ? S.primary : 'none'} strokeWidth={2} /><span style={{ fontSize: 12, fontWeight: 700, color: hasVoted ? S.primary : S.muted }}>{votes[i]}</span></button><div style={{ flex: 1 }}><div style={{ fontWeight: 600, fontSize: 13, color: S.ink, marginBottom: 5 }}>{f.title}</div><div style={{ display: 'flex', gap: 7 }}><span style={{ background: s.bg, color: s.color, fontSize: 10, fontWeight: 700, padding: '2px 8px', borderRadius: 100, textTransform: 'uppercase' }}>{s.label}</span><span style={{ fontSize: 11, color: S.muted }}>{f.category}</span></div></div></Card>); })}</div></div><div><Card><h3 style={{ fontWeight: 700, fontSize: 15, color: S.ink, marginBottom: 16, fontFamily: 'var(--font-display)', letterSpacing: '-0.2px' }}>{submitted ? '✓ Thanks!' : 'Suggest a feature'}</h3>{submitted ? (<div><p style={{ fontSize: 13, color: S.muted, marginBottom: 14, lineHeight: 1.65 }}>We read every request. If it fits the roadmap, it&apos;ll show up on the board.</p><Btn size="sm" variant="ghost" onClick={() => { setSubmitted(false); setForm({ title: '', description: '', category: 'Platform' }) }}>Submit another</Btn></div>) : (<div><Field label="Title"><input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="What should we build?" style={{ width: '100%', padding: '9px 12px', border: `1px solid ${S.border}`, borderRadius: 8, fontSize: 13, fontFamily: 'var(--font-body)', outline: 'none', color: S.ink, background: '#fff', transition: 'border-color 0.15s' }} onFocus={e => e.target.style.borderColor = S.primary} onBlur={e => e.target.style.borderColor = S.border} /></Field><Field label="Category"><div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>{categories.map(c => <button type="button" key={c} onClick={() => setForm({ ...form, category: c })} style={{ padding: '4px 10px', borderRadius: 100, border: `1px solid ${form.category === c ? S.primary : S.border}`, background: form.category === c ? S.accentBg2 : '#fff', color: form.category === c ? S.primary : S.inkSecondary, fontSize: 11, fontWeight: 600, cursor: 'pointer', fontFamily: 'var(--font-body)', transition: 'all 0.15s' }}>{c}</button>)}</div></Field><Field label="Why do you need this?"><textarea value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} placeholder="What problem does it solve?" rows={3} style={{ width: '100%', padding: '9px 12px', border: `1px solid ${S.border}`, borderRadius: 8, fontSize: 13, fontFamily: 'var(--font-body)', outline: 'none', color: S.ink, background: '#fff', resize: 'vertical', transition: 'border-color 0.15s' }} onFocus={e => e.target.style.borderColor = S.primary} onBlur={e => e.target.style.borderColor = S.border} /></Field><Btn onClick={() => form.title && setSubmitted(true)} disabled={!form.title} style={{ width: '100%', justifyContent: 'center' }}>Submit Request</Btn></div>)}</Card></div></div></div>); }

const NAV = [
  { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, group: 'CORE' },
  { id: 'intake', label: 'Intake', icon: Inbox, group: 'CORE' },
  { id: 'ramp', label: 'Ramp & Onboarding', icon: Users, group: 'CORE' },
  { id: 'notes', label: '1:1 Notes', icon: MessageSquare, group: 'CORE' },
  { id: 'collaterals', label: 'Collaterals', icon: BookOpen, group: 'CORE' },
  { id: 'sessions', label: 'Sessions', icon: Video, group: 'CORE' },
  { id: 'pulse', label: 'Pulse Checks', icon: Activity, group: 'OPERATIONS' },
  { id: 'planning', label: 'Weekly Planning', icon: Calendar, group: 'OPERATIONS' },
  { id: 'forecasting', label: 'Forecasting', icon: TrendingUp, group: 'OPERATIONS' },
  { id: 'leaderboards', label: 'Leaderboards', icon: Trophy, group: 'OPERATIONS' },
  { id: 'settings', label: 'Settings', icon: Settings, group: null },
  { id: 'featurereqs', label: 'Feature Requests', icon: Star, group: null },
]

export default function App() {
  const [user, setUser] = useState(null)
  const [loading, setLoading] = useState(true)
  const [activeTab, setActiveTab] = useState('dashboard')
  const [showWalkthrough, setShowWalkthrough] = useState(false)
  const [workspaceId, setWorkspaceId] = useState(null)
  const [userRole, setUserRole] = useState('member')
  const router = useRouter()

  useEffect(() => {
    async function init() {
      const { data: { session } } = await supabase.auth.getSession()
      if (!session) { router.push('/login'); return }
      const user = session.user; setUser(user)
      const { data: membership } = await supabase.from('workspace_members').select('workspace_id, role').eq('user_id', user.id).single()
      if (membership) {
        setWorkspaceId(membership.workspace_id); setUserRole(membership.role); setLoading(false)
        const seen = localStorage.getItem(`eos_walked_${user.id}`)
        if (!seen) { setTimeout(() => setShowWalkthrough(true), 600); localStorage.setItem(`eos_walked_${user.id}`, '1') }
      } else {
        await supabase.auth.signOut(); router.push('/login?error=no_workspace')
      }
    }
    init()
    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => { if (event === 'SIGNED_IN' && session) init() })
    return () => subscription.unsubscribe()
  }, [router])

  const signOut = async () => { await supabase.auth.signOut(); router.push('/login') }

  if (loading) return (
    <div style={{ height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: S.ink }}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ margin: '0 auto 24px' }}><SidebarLogo /></div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, justifyContent: 'center' }}>
          <Loader size={16} color={S.primaryLight} style={{ animation: 'spin 1s linear infinite' }} />
          <span style={{ color: S.primaryLight, fontSize: 14, fontFamily: 'var(--font-body)', fontWeight: 500 }}>Setting up your workspace...</span>
        </div>
        <div style={{ marginTop: 16, height: 3, width: 180, background: 'rgba(124,92,252,0.15)', borderRadius: 2, overflow: 'hidden', margin: '16px auto 0' }}>
          <div style={{ height: '100%', width: '60%', background: `linear-gradient(90deg, ${S.primary}, ${S.primaryHover})`, borderRadius: 2, animation: 'loadBar 1.5s ease-in-out infinite' }} />
        </div>
      </div>
    </div>
  )

  const sharedProps = { userId: user.id, workspaceId }

  const renderView = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard {...sharedProps} onNavigate={setActiveTab} />
      case 'intake': return <Intake {...sharedProps} />
      case 'ramp': return <Ramp {...sharedProps} />
      case 'notes': return <Notes {...sharedProps} />
      case 'collaterals': return <Collaterals {...sharedProps} />
      case 'sessions': return <Sessions {...sharedProps} />
      case 'pulse': return <PulseChecks {...sharedProps} />
      case 'planning': return <WeeklyPlanning {...sharedProps} />
      case 'forecasting': return <Forecasting {...sharedProps} />
      case 'leaderboards': return <Leaderboards {...sharedProps} />
      case 'settings': return <SettingsPanel user={user} workspaceId={workspaceId} userRole={userRole} onSignOut={signOut} onReplayWalkthrough={() => setShowWalkthrough(true)} />
      case 'featurereqs': return <FeatureRequests />
      default: return <Dashboard {...sharedProps} onNavigate={setActiveTab} />
    }
  }

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Caveat:wght@400;500;600;700&family=Libre+Baskerville:ital,wght@0,400;0,700;1,400&family=Sora:wght@300;400;500;600;700&display=swap');
        :root { --font-display: 'Libre Baskerville', Georgia, serif; --font-body: 'Sora', sans-serif; }
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: var(--font-body); -webkit-font-smoothing: antialiased; background: ${S.canvas}; }
        input, select, textarea, button { font-family: var(--font-body); }
        a { text-decoration: none; }
        @keyframes spin { from { transform: rotate(0deg) } to { transform: rotate(360deg) } }      
        @keyframes loadBar { 0% { width: 0%; margin-left: 0% } 50% { width: 60%; margin-left: 20% } 100% { width: 0%; margin-left: 100% } }
        @keyframes toastIn { from { opacity: 0; transform: translateY(10px) } to { opacity: 1; transform: translateY(0) } }
      `}</style>
      <div style={{ display: 'flex', height: '100vh', background: S.canvas, overflow: 'hidden' }}>
        <ToastContainer />
        {showWalkthrough && <Walkthrough onClose={() => setShowWalkthrough(false)} onNavigate={setActiveTab} />}
        <div style={{ width: S.sidebar.width, background: S.sidebar.background, display: 'flex', flexDirection: 'column', flexShrink: 0, overflowY: 'auto' }}>
          <a href="/" title="Back to enableos.app" style={{ display: 'block', padding: '20px 16px 16px', borderBottom: '1px solid rgba(155,126,255,0.14)', background: 'linear-gradient(180deg, rgba(124,92,252,0.07), transparent)', textDecoration: 'none' }}>
            <SidebarLogo />
          </a>
          <nav style={{ flex: 1, padding: '16px 12px' }}>
            {['CORE', 'OPERATIONS'].map(group => (
              <div key={group} style={{ marginBottom: 24 }}>
                <div style={{ fontSize: 9, fontWeight: 700, color: 'rgba(255,255,255,0.28)', letterSpacing: '0.12em', padding: '0 8px', marginBottom: 6, textTransform: 'uppercase' }}>{group}</div>
                {NAV.filter(n => n.group === group).map(item => {
                  const active = activeTab === item.id
                  return (
                    <button key={item.id} onClick={() => setActiveTab(item.id)}
                      style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '9px 10px', borderRadius: 8, border: 'none', cursor: 'pointer', background: active ? 'linear-gradient(90deg, rgba(124,92,252,0.22), rgba(124,92,252,0.06))' : 'transparent', color: active ? '#fff' : 'rgba(255,255,255,0.48)', fontSize: 13, fontWeight: active ? 600 : 400, fontFamily: 'var(--font-body)', marginBottom: 2, transition: 'all 0.15s', textAlign: 'left', borderLeft: active ? `2px solid ${S.primaryHover}` : '2px solid transparent' }}
                      onMouseEnter={e => { if (!active) { e.currentTarget.style.background = 'rgba(255,255,255,0.06)'; e.currentTarget.style.color = 'rgba(255,255,255,0.75)' } }}
                      onMouseLeave={e => { if (!active) { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'rgba(255,255,255,0.48)' } }}
                    >
                      <item.icon size={16} />{item.label}
                    </button>
                  )
                })}
              </div>
            ))}
            <div style={{ borderTop: '1px solid rgba(155,126,255,0.1)', paddingTop: 16 }}>
              {NAV.filter(n => n.group === null).map(item => {
                const active = activeTab === item.id
                return (
                  <button key={item.id} onClick={() => setActiveTab(item.id)}
                    style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '9px 10px', borderRadius: 8, border: 'none', cursor: 'pointer', background: active ? 'linear-gradient(90deg, rgba(124,92,252,0.22), rgba(124,92,252,0.06))' : 'transparent', color: active ? '#fff' : 'rgba(255,255,255,0.48)', fontSize: 13, fontWeight: active ? 600 : 400, fontFamily: 'var(--font-body)', transition: 'all 0.15s', textAlign: 'left', borderLeft: active ? `2px solid ${S.primaryHover}` : '2px solid transparent', marginBottom: 2 }}
                    onMouseEnter={e => { if (!active) { e.currentTarget.style.background = 'rgba(255,255,255,0.06)'; e.currentTarget.style.color = 'rgba(255,255,255,0.75)' } }}
                    onMouseLeave={e => { if (!active) { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'rgba(255,255,255,0.48)' } }}
                  >
                    <item.icon size={16} />{item.label}
                  </button>
                )
              })}
              <a href="/roadmap" target="_blank" rel="noreferrer"
                style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '9px 10px', borderRadius: 8, color: 'rgba(255,255,255,0.48)', fontSize: 13, fontWeight: 400, fontFamily: 'var(--font-body)', textDecoration: 'none', borderLeft: '2px solid transparent', marginTop: 2, transition: 'all 0.15s' }}
                onMouseEnter={e => { e.currentTarget.style.color = 'rgba(255,255,255,0.75)'; e.currentTarget.style.background = 'rgba(255,255,255,0.06)' }}
                onMouseLeave={e => { e.currentTarget.style.color = 'rgba(255,255,255,0.48)'; e.currentTarget.style.background = 'transparent' }}
              >
                <TrendingUp size={16} />Roadmap
              </a>
            </div>
          </nav>
          <div style={{ padding: '14px 16px 18px', borderTop: '1px solid rgba(155,126,255,0.1)' }}>
            {user?.email === ADMIN_EMAIL && <WorkspaceSwitcher current="personal" />}
            <button onClick={() => setShowWalkthrough(true)}
              style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 7, padding: '7px 10px', borderRadius: 7, border: 'none', background: 'rgba(124,92,252,0.12)', color: '#BDA9FF', fontSize: 11, fontWeight: 600, cursor: 'pointer', fontFamily: 'var(--font-body)', marginBottom: 12, transition: 'background 0.15s' }}
              onMouseEnter={e => e.currentTarget.style.background = 'rgba(124,92,252,0.2)'}
              onMouseLeave={e => e.currentTarget.style.background = 'rgba(124,92,252,0.12)'}>
              <Sparkles size={12} />Replay walkthrough
            </button>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <div style={{ width: 32, height: 32, borderRadius: '50%', background: `linear-gradient(135deg, ${S.primary}, #a78bfa)`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                <span style={{ color: '#fff', fontSize: 13, fontWeight: 700 }}>{user?.email?.[0]?.toUpperCase()}</span>
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 12, color: '#fff', fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{user?.email}</div>
                <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.38)' }}>{userRole === 'admin' ? 'Admin' : 'Member'}</div>
              </div>
            </div>
          </div>
        </div>
        <div style={{ flex: 1, overflowY: 'auto', padding: '36px 40px' }}>
          {renderView()}
        </div>
      </div>
    </>
  )
}
